
import React, {useState, useEffect} from "react";

// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import { TextField, CircularProgress } from "@material-ui/core";

// @material-ui/icons
import SearchIcon from '@material-ui/icons/Search';
import SelectAllIcon from '@material-ui/icons/SelectAll';
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import NavPills from "components/NavPills/NavPills.js";
import Card from "components/Card/Card.js";
import CardBody from "components/Card/CardBody.js";
import CardIcon from "components/Card/CardIcon.js";
import Table from "components/Table/Table.js";
import CardHeader from "components/Card/CardHeader.js";
import axios from "axios";
import { cardTitle } from "assets/jss/material-dashboard-pro-react.js";
import { Animated } from "react-animated-css";
import BlockChain from "./BlockChain";
import VerticalLinearStepper from "../../Components/Stepper";
import Tags from "./Tags";
import Approval from "./Approval";
import Review from "./Review";
import Autocomplete from '@material-ui/lab/Autocomplete';
import dateFormat from "dateformat";

const styles = {
  cardIconTitle: {
    ...cardTitle,
    marginTop: "15px",
    marginBottom: "0px",
  },
  cardTitleText: {
    color: "white",
  },
  buttonRight: {},
};

const useStyles = makeStyles(styles);

  function sleep(delay = 0) {
    return new Promise((resolve) => {
      setTimeout(resolve, delay);
    });
  }
export default function Verify() {
    const[animateFileInfo, setAnimateFileInfo] = useState(false);
    const[disabledSearch, setDisabledSearch] = useState(true);
    const[isSearching, setIsSearching] = useState(false);
    const [fileName, setFileName] = React.useState(null);
    const [Selected, setSelected] = React.useState(null);
    const [fileData, setFileData] = React.useState([]);
    const [blockChainData, setBlockChainData] = React.useState(null);
    const [file, setFile] = React.useState(null);
    
    
    const selectFile = (fileObject,index) => {
       console.log(fileObject);
        // document.getElementById("selectFile"+index).setAttribute("color","black")
        if(Selected == index){
          setSelected(null);
          setFile(null);
          setBlockChainData(null);
        }else{
          const Check = require("is-null-empty-or-undefined").Check;
          if(typeof fileObject.fileId !== "undefined" && !Check(fileObject.fileId)){
            axios({
              method: "get", //you can set what request you want to be
              // url: `${process.env.REACT_APP_LDOCS_API_BOOKCHAIN_URL}/api/queryhistory/${fileObject.fileId}`
              url: `${process.env.REACT_APP_LDOCS_API_BOOKCHAIN_URL}/api/queryhistory/4b41a3475132bd861b30a878e30aa56a-waqas-sample_pdf_27.pdf`
            })
              .then((response) => {
                console.log(response.data);
                setBlockChainData(response.data)
                setSelected(index);
              setFile(fileObject);
              })
              .catch((error) => {
                setSelected(index);
              setFile(fileObject);
                setBlockChainData(null)
                console.log(
                  typeof error.response != "undefined"
                    ? error.response.data
                    : error.message
                );
              });
          }else{
            setSelected(index);
              setFile(fileObject);
              setBlockChainData(null);
          }
        }
        
        
    }

    const classes = useStyles();

    const getFile = () => {
        setBlockChainData(null);
        setSelected(null);
        setFile(null);
        setAnimateFileInfo(false);
        setIsSearching(true);
        axios({
          method: "get", //you can set what request you want to be
          url: `${process.env.REACT_APP_LDOCS_API_URL}/files/getfilewt_detail/${fileName.name}`
        })
          .then((response) => {
            setFileData(response.data);
            setAnimateFileInfo(true);
            setIsSearching(false);
          })
          .catch((error) => {
            setFileData([]);
            console.log(
              typeof error.response != "undefined"
                ? error.response.data
                : error.message
            );
            setAnimateFileInfo(true);
            setIsSearching(false);
          });
    };
//   Test Data
const [open, setOpen] = React.useState(false);
  const [options, setOptions] = React.useState([]);
  const [backupOptions, setBackupOptions] = React.useState([]);
  const loading = open && options.length === 0;

  React.useEffect(() => {
    let active = true;

    if (!loading) {
      return undefined;
    }

    (async () => {
        if(options.length <= 0){
            const response = await fetch(`${process.env.REACT_APP_LDOCS_API_URL}/files/getfilewt`);
            await sleep(130);
            const files = await response.json();

            if (active) {
                setOptions(files.map((item) =>{ return {name: item} } ));
            }
        }else{
            await sleep(500);
            setOptions(backupOptions)
        }
    })();

    return () => {
      active = false;
    };
  }, [loading]);
  React.useEffect(() => {
    if (!open) {
        setBackupOptions(options);
      setOptions([]);
    }
  }, [open]);
  return (
    <div>
      <Animated
        animationIn="bounceInRight"
        animationOut="bounceOutLeft"
        animationInDuration={1000}
        animationOutDuration={1000}
        isVisible={true}
      >
        <GridContainer>
          <GridItem xs={12}>
            <Card>
              <CardHeader color="info" icon>
                <CardIcon color="info">
                  <h4 className={classes.cardTitleText}>Search File</h4>
                </CardIcon>
              </CardHeader>
              <CardBody>
                  <GridContainer>
                    <GridItem
                        xs={12}
                        sm={12}
                        md={10}
                        lg={10}
                        style={{ marginTop: "10px", marginBottom: "10px" }}
                        >
                            <Autocomplete
                                id="documentname"
                                value={fileName}
                                onChange={(event, newValue) => {
                                    setFileName(newValue);
                                    if(newValue !== null){
                                        setDisabledSearch(false)
                                    }else{
                                        setDisabledSearch(true)
                                    }
                                }}
                                open={open}
                                onOpen={() => {
                                    setOpen(true);
                                }}
                                onClose={() => {
                                    setOpen(false);
                                }}
                                getOptionSelected={(option, value) => option.name === value.name}
                                getOptionLabel={(option) => option.name}
                                options={options}
                                loading={loading}
                                renderInput={(params) => (
                                    <TextField
                                    {...params}
                                    label="Document Name"
                                    InputProps={{
                                        ...params.InputProps,
                                        endAdornment: (
                                        <React.Fragment>
                                            {loading ? <CircularProgress color="inherit" size={20} /> : null}
                                            
                                            {params.InputProps.endAdornment}
                                        </React.Fragment>
                                        ),
                                    }}
                                    />
                                )}
                                />
                            </GridItem>
                        <GridItem
                            xs={12}
                            sm={12}
                            md={2}
                            lg={2}
                            style={{ marginTop: "10px", marginBottom: "10px" }}
                        >
                            <Button
                                color="rose"
                                className={classes.registerButton}
                                type="submit"
                                size="sm"
                                round
                                block
                                onClick={getFile}
                                disabled={disabledSearch}
                            >
                                {isSearching ? <CircularProgress color="inherit" size={20} /> : <SearchIcon />}
                            </Button>
                        </GridItem>
                    </GridContainer>
              </CardBody>
            </Card>
          </GridItem>
        </GridContainer>
        </Animated>
        <Animated
        animationIn="bounceInUp"
        animationOut="bounceOutDown"
        animationInDuration={1000}
        animationOutDuration={1000}
        isVisible={animateFileInfo}
      >
        <GridContainer>
            <GridItem xs={12}>
            <GridContainer>
                <GridItem lg={12} md={12} sm={12} xs={12}>
                <Card>
                <CardHeader color="info" icon>
                    <CardIcon color="info">
                    <h4 className={classes.cardTitleText}>File Info</h4>
                    </CardIcon>
                </CardHeader>
                <CardBody>
                {fileData.length > 0 ? 
                <Table
                    hover
                    tableHeaderColor="info"
                    tableShopping={true}
                    tableHead={[
                        "ID",
                        "Name",
                        "Hash",
                        "Version",
                        "Owner",
                        "Date",
                        "Action"
                    ]}
                    tableData={fileData.map((file,index)=>{return [index+1, file.fileName, file.fileHash, file.version,file.fileOwner, dateFormat(file.fileInitDate, "dd/mm/yyyy hh:mm:ss"),(<Button
                        round
                        color={Selected == index ? "rose" : "info"}
                        className="Edit"
                        id={"selectFile"+index}
                        name={"selectFile"+index}
                        onClick={()=>selectFile(file,index)}
                        size="sm"
                      >
                        {/* <SelectAllIcon /> */}
                        {Selected == index ? "Selected" : "select"}
                      </Button>)]}) }
                    />
                    :""}
                </CardBody>
                </Card>
            </GridItem>
            <GridItem lg={12} md={12} sm={12} xs={12}>
                 <Card>
                <CardBody>
                    <NavPills
                            color="info"
                            tabs={[
                            {
                                tabButton: "Blockchain",
                                tabContent: (
                                <span>
                                    {file !== null && blockChainData !== null ? 
                                    //<BlockChain file={blockChainData} />
                                    <VerticalLinearStepper data={blockChainData} />
                                    :
                                    file == null ? "Please select a file" : "No Data Available"}
                                </span>
                                )
                            },
                            // {
                            //     tabButton: "Approval",
                            //     tabContent: (
                            //     <span>
                            //       {file !== null && blockChainData !== null ? <Approval file={blockChainData} /> : file == null ? "Please select a file" : "No Data Available"}
                            //     </span>
                            //     )
                            // },
                            // {
                            //     tabButton: "Review",
                            //     tabContent: (
                            //     <span>
                            //         {file !== null  && blockChainData !== null ? <Review file={blockChainData} /> : file == null ? "Please select a file" : "No Data Available"}
                            //     </span>
                            //     )
                            // },
                            {
                              tabButton: "Tags",
                              tabContent: (
                              <span>
                                {file !== null ? <Tags file={file} /> : "Please select a file"}
                              </span>
                              )
                            }
                            ]}
                        />
                    </CardBody>
                  </Card>
                </GridItem>
            </GridContainer>
            </GridItem>
        </GridContainer>
        </Animated>
    </div>
  );
}
