/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  MenuItem,
  makeStyles,
  CircularProgress,
  TextField,
  Input,
  InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import CryptoJS from "crypto-js";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function UploadFile(props) {
  // register form

  const [formState, setFormState] = useState({
    isRegistering: false,
    values: {
      classification: "",
      fileSecurity: "",
      fileUpload: null,
      fileInitComments: "",
      authorAlias: "",
      authorType: ""
    },
    errors: {
      classification: "",
      fileSecurity: "",
      fileUpload: "",
      fileInitComments: "",
      authorAlias: "",
      authorType: ""
    },
  });
  const [classifications, setClassifications] = useState(['Classified','Public','Internal','None']);
  const [securities, setSecurities] = useState(['Published','Secret','Top-Secret','Confidential']);
      const classes = useStyles();
      const sweetClass = sweetAlertStyle();
      const [alert, setAlert] = React.useState(null);
      const successAlert = (msg) => {
        setAlert(
          <SweetAlert
            success
            style={{ display: "block", marginTop: "-100px" }}
            title="Success!"
            onConfirm={() => hideAlert()}
            onCancel={() => hideAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
          >
            {msg}
          </SweetAlert>
        );
      };
      const errorAlert = (msg) => {
        setAlert(
          <SweetAlert
            error
            style={{ display: "block", marginTop: "-100px" }}
            title="Error!"
            onConfirm={() => hideErrorAlert()}
            onCancel={() => hideErrorAlert()}
            confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
          >
            {msg}
            <br />
            For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
          </SweetAlert>
        );
      };
      const hideAlert = () => {
        closeModal();
        setAlert(null);
      };
      const hideErrorAlert = () => {
        setAlert(null);
      };
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
  const handleFileChange = (event) => {
     let file = event.target.files[0];
    if (!file.type.match("application/pdf")) {
      errorAlert("Only PDF Files Accepted");
      // $("#fileUpload").val("");
      document.getElementById("fileUpload").value = "";
      return false;
    } else {
      setFormState((formState) => ({
        ...formState,
        values: {
          ...formState.values,
          [event.target.name]: file,
        },
      }));
    }
  };
  function closeModal() {
    document.getElementById("fileUpload").value = "";
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        classification: "",
        fileSecurity: "",
        fileUpload: null,
        fileInitComments: "",
      },
      errors: {
        ...formState.errors,
        classification: "",
        fileSecurity: "",
        fileUpload: "",
        fileInitComments: "",
      },
    }));
    props.closeModal();
  }
 const calculateMd5 = (file, callback) => {
    try {
      var reader = new FileReader();
      reader.readAsArrayBuffer(file);
      reader.onloadend = function() {
        var wordArray = CryptoJS.lib.WordArray.create(reader.result),
          hash = CryptoJS.MD5(wordArray).toString();
        // or CryptoJS.SHA256(wordArray).toString(); for SHA-2
        callback(hash);
      };
    } catch (err) {
      callback(err);
    }
  }
  const handleRegister = (e) => {
    e.preventDefault();
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let classification;
    let fileSecurity;
    let fileUpload;
    let authorAlias;
    let authorType;
    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;

    if (!Check(formState.values.fileUpload)) {
      fileUpload = "success";
    } else {
      fileUpload = "error";
      error = true;
    }
    if (!Check(formState.values.fileSecurity)) {
      fileSecurity = "success";
    } else {
      fileSecurity = "error";
      error = true;
    }
    if (!Check(formState.values.classification)) {
      classification = "success";
    } else {
      classification = "error";
      error = true;
    }
    
    if (!Check(formState.values.authorType)) {
      authorType = "success";
    } else {
      authorType = "error";
      error = true;
    }
    if (!Check(formState.values.authorAlias)) {
      authorAlias = "success";
    } else {
      authorAlias = "error";
      error = true;
    }

    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        classification: classification,
        fileSecurity: fileSecurity,
        fileUpload: fileUpload,
        authorType:authorType,
        authorAlias:authorAlias
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
      }));
      return false;
    } else {
    
      let comments = "";
      if (!Check(formState.values.fileInitComments)) {
        comments = formState.values.fileInitComments;
      } else {
        comments = "First version upload";
      }
      let msg = "";
      let Token = localStorage.getItem("cooljwt");
      let decoded = jwt.decode(Token);
      console.log(decoded);
    calculateMd5(formState.values.fileUpload, (hash, err) => {
      if (hash) {
        var bodyFormData = new FormData();
        bodyFormData.append("file", formState.values.fileUpload);
        bodyFormData.append("fileInitSecrecy", formState.values.fileSecurity);
        bodyFormData.append(
          "fileInitClassification",
          formState.values.classification
        );
        bodyFormData.append("fileHash", hash);
        bodyFormData.append("filePath", "http://");
        bodyFormData.append("loginName", decoded.loginName);
        bodyFormData.append("fileInitDate", new Date());
        bodyFormData.append("fileInitComments", comments);
        bodyFormData.append("discardFile", "");
        bodyFormData.append("parentHash", "");
        bodyFormData.append("version", "");
        bodyFormData.append('locationID', decoded.locationID);
        bodyFormData.append("accessGroupd", "financeteam");
        bodyFormData.append("authorType", formState.values.authorType);
        bodyFormData.append("authorAlias", formState.values.authorAlias);
        axios({
          method: "post",
          url: `${process.env.REACT_APP_LDOCS_API_URL}/file/upload_new`,
          data: bodyFormData,
          headers: { "Content-Type": "multipart/form-data", cooljwt: Token },
        })
          .then((response) => {
            props.getMyFiles();
            document.getElementById("fileUpload").value = "";
            setFormState((formState) => ({
              ...formState,
              message: "File has been successfully uploaded!",
              isRegistering: false,
            }));
            msg = "File Uploaded Successfully!";
            successAlert(msg);
          })
          .catch((error) => {
            setFormState((formState) => ({
              ...formState,
              message:
                typeof error.response != "undefined"
                  ? error.response.data
                  : error.message,
              isRegistering: false,
            }));
            msg =
              typeof error.response != "undefined"
                ? error.response.data
                : error.message;
            errorAlert(msg);
          });
      }
      if (err) errorAlert("Failed to create file hash");
    });
  }
};
  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Upload File</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <form onSubmit={handleRegister}>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "20px", marginBottom: "20px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.fileUpload === "error"}
                    helperText={
                      formState.errors.fileUpload === "error"
                        ? "Valid fileUpload is required"
                        : null
                    }
                    label="Select a file to upload"
                    InputLabelProps={{
                      shrink: true,
                    }}
                    id="fileUpload"
                    name="fileUpload"
                    onChange={(event) => {
                      handleFileChange(event);
                    }}
                    type="file"
                    accept="application/pdf"
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.classification === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.classification === "error"
                        ? "Please select file classification"
                        : null
                    }
                    label="File Classification"
                    name="classification"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.classification || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Classification
                    </MenuItem>

                    {classifications.map((classif, index) => {
                      return (
                        <MenuItem key={index} value={classif.toUpperCase()}>
                          {classif.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.fileSecurity === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.fileSecurity === "error"
                        ? "Please select file security"
                        : null
                    }
                    label="File Security"
                    name="fileSecurity"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.fileSecurity || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Security Options
                    </MenuItem>
                    {securities.map((security, index) => {
                      return (
                        <MenuItem key={index} value={security.toUpperCase()}>
                          {security.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.authorType === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.authorType === "error"
                        ? "Please select Author Type"
                        : null
                    }
                    label="Author Type"
                    name="authorType"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.authorType || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Author Type
                    </MenuItem>
                        <MenuItem value={"INTERNAL"}>
                          INTERNAL
                        </MenuItem>
                        <MenuItem value={"EXTERNAL"}>
                          EXTERNAL
                        </MenuItem>
                      
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginBottom: "20px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.authorAlias === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.authorAlias === "error"
                        ? "Please enter Author Alias"
                        : null
                    }
                    label="Author Alias"
                    name="authorAlias"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    value={formState.values.authorAlias || ""}
                  >
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.fileInitComments === "error"}
                    helperText={
                      formState.errors.fileInitComments === "error"
                        ? "Valid Comments is required"
                        : null
                    }
                    label="File Comments"
                    id="fileInitComments"
                    name="fileInitComments"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <MessageIcon />
                        </InputAdornment>
                      ),
                    }}
                    type="text"
                    value={formState.values.fileInitComments || ""}
                  />
                </GridItem>
              </GridContainer>

              <Button
                color="info"
                className={classes.registerButton}
                round
                type="submit"
              >
                Upload File
              </Button>
              {formState.isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </form>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
