import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  makeStyles,
  CircularProgress,
  LinearProgress,
  Grid,
  List,
  ListItem,
  ListItemIcon,
  ListItemAvatar,
  ListItemSecondaryAction,
  ListItemText,
  Tooltip,
  Avatar,
  IconButton,
  Divider,
  ListSubheader,
} from "@material-ui/core";

import FolderIcon from "@material-ui/icons/Folder";
import DeleteIcon from "@material-ui/icons/Delete";
import InboxIcon from "@material-ui/icons/Inbox";
import DraftsIcon from "@material-ui/icons/Drafts";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

let Token = localStorage.getItem("cooljwt");
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function FileShare(props) {
  // register form
    const classes = useStyles();
    
    const [dense, setDense] = React.useState(false);
    const [secondary, setSecondary] = React.useState(false);
    const [isLoading, setIsLoading] = React.useState(true);
    const [teamDelete, setTeamDelete] = React.useState(false);
    const [deptDelete, setDeptDelete] = React.useState(false);
    const [compDelete, setCompDelete] = React.useState(false);
    const [orgDelete, setOrgDelete] = React.useState(false);
    const [userDelete, setUserDelete] = React.useState(false);

    const [sharedData, setSharedData] = React.useState([]);
    const [selectedIndex, setSelectedIndex] = React.useState(1);

    const deleteListItem = (record, type) => {
        let file = props.fileData;
        let decoded = jwt.decode(Token);

        let data = {};

        if (type == "Team") {
            setTeamDelete(true);
            data = {
                team: record.teamName,
                department: decoded.d,
                company: decoded.c,
                organization: decoded.o,
                fileName: file.fileName,
                fileId: file.fileId,
                fileHash: file.fileHash,
                indivisualloginname: "",
            };
        } else if (type == "Department") {
            setDeptDelete(true);
            data = {
              team: "",
              department: record.deptname,
              company: decoded.c,
              organization: decoded.o,
              fileName: file.fileName,
              fileId: file.fileId,
              fileHash: file.fileHash,
              indivisualloginname: "",
            };
        } else if (type == "Company") {
            setCompDelete(true);
            data = {
              team: "",
              department: "",
              company: record.compname,
              organization: decoded.o,
              fileName: file.fileName,
              fileId: file.fileId,
              fileHash: file.fileHash,
              indivisualloginname: "",
            };
        } else if (type == "Organization") {
            setOrgDelete(true)
            data = {
              team: "",
              department: "",
              company: "",
              organization: record.orgName,
              fileName: file.fileName,
              fileId: file.fileId,
              fileHash: file.fileHash,
              indivisualloginname: "",
            };
        } else if (type == "User") {
            setUserDelete(true);
            let accessUser = sharedData.accessUser.filter(
              (itm) => itm != record
            );
            data = {
              team: "",
              department: "",
              company: "",
              organization: "",
              fileName: file.fileName,
              fileId: file.fileId,
              fileHash: file.fileHash,
              indivisualloginname: accessUser,
            };
        }

        axios({
          method: "POST",
            url: `${process.env.REACT_APP_LDOCS_API_URL}/fileshare/removeshare_bysameID`,
          data: data,
          headers: {
            cooljwt: Token,
          },
        })
            .then((response) => {
                let accessTeam = sharedData.accessTeam.filter(itm => itm._id != record._id);
                let accessdept = sharedData.accessdept.filter(itm => itm._id != record._id);
                let accessComp = sharedData.accessComp.filter(itm => itm._id != record._id);
                let accessOrg = sharedData.accessOrg.filter(itm => itm._id != record._id);
                let accessUser = sharedData.accessUser.filter(
                  (itm) => itm != record
                );
                let data = {
                    accessTeam: accessTeam,
                    accessdept: accessdept,
                    accessComp: accessComp,
                    accessOrg: accessOrg,
                    accessUser: accessUser
                }
            setSharedData(data);
                setTeamDelete(false);
                setDeptDelete(false);
                setCompDelete(false);
                setOrgDelete(false);
                setUserDelete(false);
            successAlert("File Sharing Removed Successfully!");
          })
            .catch((error) => {
                setTeamDelete(false);
                setDeptDelete(false);
                setCompDelete(false);
                setOrgDelete(false);
                setUserDelete(false);
            console.log(
              typeof error.response != "undefined"
                ? error.response.data
                : error.message
            );
            errorAlert(
              typeof error.response != "undefined"
                ? error.response.data
                : error.message
            );
          });
    };

  const sweetClass = sweetAlertStyle();
  const [alert, setAlert] = React.useState(null);
  const successAlert = (msg) => {
    setAlert(
      <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
      >
        {msg}
      </SweetAlert>
    );
  };
  const errorAlert = (msg) => {
    setAlert(
      <SweetAlert
        error
        style={{ display: "block", marginTop: "-100px" }}
        title="Error!"
        onConfirm={() => hideErrorAlert()}
        onCancel={() => hideErrorAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
      >
        {msg}
        <br />
        For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
      </SweetAlert>
    );
  };
  const hideAlert = () => {
    setAlert(null);
  };
  const hideErrorAlert = () => {
    setAlert(null);
  };
  function closeModal() {
    props.closeShareModal();
  }
const getShareHistory = () => {
  let file = props.fileData;
    let url = `${process.env.REACT_APP_LDOCS_API_URL}/fileshare/share_details_userfile/${file.fileName}/${file.fileId}/${file.fileHash}`;
  axios({
    method: "GET",
    url: url,
    headers: {
      cooljwt: Token,
    },
  })
      .then((response) => {
          setSharedData(response.data);
      setIsLoading(false);
    })
      .catch((error) => {
         let data = {
           accessTeam: [],
           accessdept: [],
           accessComp: [],
           accessOrg: [],
           accessUser: [],
          };
          setSharedData(data);
      console.log(
        typeof error.response != "undefined"
          ? error.response.data
          : error.message
      );
      setIsLoading(false);
    });
};
React.useEffect(() => {
  getShareHistory();
}, []);

  return (
    <GridContainer>
      {alert}
      {isLoading ? (
        <CircularProgress />
      ) : (
        <GridItem xs={12} sm={12} md={12}>
          <Card>
            <CardHeader color="info" icon>
              <CardIcon color="info">
                <h4 className={classes.cardTitle}>File Shared With</h4>
              </CardIcon>
            </CardHeader>
            <CardBody>
              <GridContainer>
                <Grid item xs={12} md={6}>
                  <div className={classes.root}>
                    <List
                      subheader={
                        <ListSubheader
                          style={{
                            backgroundColor: "#00B7CB",
                            color: "white",
                          }}
                        >
                          Team
                          {teamDelete ? <LinearProgress /> : ""}
                        </ListSubheader>
                      }
                      component="nav"
                      aria-label="main mailbox folders"
                    >
                      {sharedData.accessTeam.length > 0 ? 
                        sharedData.accessTeam.map((itm, index) => {
                          return (
                            <React.Fragment key={index}>
                              <Tooltip
                                title={itm.helperText}
                                aria-label="viewfile"
                              >
                                <ListItem button selected={selectedIndex === 0}>
                                  <ListItemAvatar>
                                    <Avatar>
                                      <FolderIcon />
                                    </Avatar>
                                  </ListItemAvatar>
                                  <ListItemText primary={itm.teamName} />
                                  <ListItemSecondaryAction
                                    onClick={() => deleteListItem(itm, "Team")}
                                  >
                                    <IconButton edge="end" aria-label="delete">
                                      <DeleteIcon />
                                    </IconButton>
                                  </ListItemSecondaryAction>
                                </ListItem>
                              </Tooltip>
                              <Divider />
                            </React.Fragment>
                          );
                        })
                      : (
                        <ListItem button selected={selectedIndex === 0}>
                          <ListItemText primary={"Not shared with Team"} />
                        </ListItem>
                      )}
                    </List>
                  </div>
                </Grid>

                <Grid item xs={12} md={6}>
                  <div className={classes.root}>
                    <List
                      subheader={
                        <ListSubheader
                          style={{
                            backgroundColor: "#00B7CB",
                            color: "white",
                          }}
                        >
                          Department
                          {deptDelete ? <LinearProgress /> : ""}
                        </ListSubheader>
                      }
                      component="nav"
                      aria-label="main mailbox folders"
                    >
                      {sharedData.accessdept.length > 0 ? 
                        sharedData.accessdept.map((itm, index) => {
                          return (
                            <React.Fragment key={index}>
                              <Tooltip
                                title={itm.helperText}
                                aria-label="viewfile"
                              >
                                <ListItem button selected={selectedIndex === 0}>
                                  <ListItemAvatar>
                                    <Avatar>
                                      <FolderIcon />
                                    </Avatar>
                                  </ListItemAvatar>
                                  <ListItemText primary={itm.deptname} />
                                  <ListItemSecondaryAction
                                    onClick={() =>
                                      deleteListItem(itm, "Department")
                                    }
                                  >
                                    <IconButton edge="end" aria-label="delete">
                                      <DeleteIcon />
                                    </IconButton>
                                  </ListItemSecondaryAction>
                                </ListItem>
                              </Tooltip>
                              <Divider />
                            </React.Fragment>
                          );
                        })
                      : (
                        <ListItem button selected={selectedIndex === 0}>
                          <ListItemText
                            primary={"Not shared with Department"}
                          />
                        </ListItem>
                      )}
                    </List>
                  </div>
                </Grid>

                <Grid item xs={12} md={4}>
                  <div className={classes.root}>
                    <List
                      subheader={
                        <ListSubheader
                          style={{
                            backgroundColor: "#00B7CB",
                            color: "white",
                          }}
                        >
                          Company
                          {compDelete ? <LinearProgress /> : ""}
                        </ListSubheader>
                      }
                      component="nav"
                      aria-label="main mailbox folders"
                    >
                      {sharedData.accessComp.length > 0 ? 
                        sharedData.accessComp.map((itm, index) => {
                          return (
                            <React.Fragment key={index}>
                              <Tooltip
                                title={itm.helperText}
                                aria-label="viewfile"
                              >
                                <ListItem button selected={selectedIndex === 0}>
                                  <ListItemAvatar>
                                    <Avatar>
                                      <FolderIcon />
                                    </Avatar>
                                  </ListItemAvatar>
                                  <ListItemText primary={itm.compname} />
                                  <ListItemSecondaryAction
                                    onClick={() =>
                                      deleteListItem(itm, "Company")
                                    }
                                  >
                                    <IconButton edge="end" aria-label="delete">
                                      <DeleteIcon />
                                    </IconButton>
                                  </ListItemSecondaryAction>
                                </ListItem>
                              </Tooltip>
                              <Divider />
                            </React.Fragment>
                          );
                        })
                       : (
                        <ListItem button selected={selectedIndex === 0}>
                          <ListItemText primary={"Not shared with Company"} />
                        </ListItem>
                      )}
                    </List>
                  </div>
                </Grid>

                <Grid item xs={12} md={4}>
                  <div className={classes.root}>
                    <List
                      subheader={
                        <ListSubheader
                          style={{
                            backgroundColor: "#00B7CB",
                            color: "white",
                          }}
                        >
                          Organization
                          {orgDelete ? <LinearProgress /> : ""}
                        </ListSubheader>
                      }
                      component="nav"
                      aria-label="main mailbox folders"
                    >
                      {sharedData.accessOrg.length > 0 ? 
                        sharedData.accessOrg.map((itm, index) => {
                          return (
                            <React.Fragment key={index}>
                              <Tooltip
                                title={itm.helperText}
                                aria-label="viewfile"
                              >
                                <ListItem button selected={selectedIndex === 0}>
                                  <ListItemAvatar>
                                    <Avatar>
                                      <FolderIcon />
                                    </Avatar>
                                  </ListItemAvatar>
                                  <ListItemText primary={itm.orgName} />
                                  <ListItemSecondaryAction
                                    onClick={() =>
                                      deleteListItem(itm, "Organization")
                                    }
                                  >
                                    <IconButton edge="end" aria-label="delete">
                                      <DeleteIcon />
                                    </IconButton>
                                  </ListItemSecondaryAction>
                                </ListItem>
                              </Tooltip>
                              <Divider />
                            </React.Fragment>
                          );
                        })
                       : (
                        <ListItem button selected={selectedIndex === 0}>
                          <ListItemText
                            primary={"Not shared with Organization"}
                          />
                        </ListItem>
                      )}
                    </List>
                  </div>
                </Grid>

                <Grid item xs={12} md={4}>
                  <div className={classes.root}>
                    <List
                      subheader={
                        <ListSubheader
                          style={{
                            backgroundColor: "#00B7CB",
                            color: "white",
                          }}
                        >
                          Other Users
                          {userDelete ? <LinearProgress /> : ""}
                        </ListSubheader>
                      }
                      component="nav"
                      aria-label="main mailbox folders"
                    >
                      {sharedData.accessUser.length > 0 ? 
                        sharedData.accessUser.map((itm, index) => {
                          return (
                            <React.Fragment key={index}>
                              <Tooltip
                                title={`Shared With: ${itm}`}
                                aria-label="viewfile"
                              >
                                <ListItem button selected={selectedIndex === 0}>
                                  <ListItemAvatar>
                                    <Avatar>
                                      <FolderIcon />
                                    </Avatar>
                                  </ListItemAvatar>
                                  <ListItemText primary={itm} />
                                  <ListItemSecondaryAction
                                    onClick={() => deleteListItem(itm, "User")}
                                  >
                                    <IconButton edge="end" aria-label="delete">
                                      <DeleteIcon />
                                    </IconButton>
                                  </ListItemSecondaryAction>
                                </ListItem>
                              </Tooltip>
                              <Divider />
                            </React.Fragment>
                          );
                        })
                       : (
                        <ListItem button selected={selectedIndex === 0}>
                          <ListItemText
                            primary={"Not shared with any User"}
                          />
                        </ListItem>
                      )}
                    </List>
                  </div>
                </Grid>
              </GridContainer>
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </CardBody>
          </Card>
        </GridItem>
      )}
    </GridContainer>
  );
}
