import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
MenuItem,
makeStyles,
CircularProgress,
LinearProgress,
TextField,
Switch,
FormControlLabel,
InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";
// For Chips
import Chip from "@material-ui/core/Chip";
import FaceIcon from "@material-ui/icons/Face";
import DoneIcon from "@material-ui/icons/Done";
import WarningIcon from '@material-ui/icons/Warning';
import defaultAvatar from "assets/img/avatar-2.png";
import CardTravel from "@material-ui/icons/CardTravel";
import Timeline from "./TagsTimeline.js";



import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import ListItemAvatar from '@material-ui/core/ListItemAvatar';
import Avatar from '@material-ui/core/Avatar';


import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import ChipInput from "material-ui-chip-input";
import convertUrlToImageData from "./getFileFromUrl";

 
import { sendNotification, getNotification, sendEventLog } from "actions";
import { useSelector, useDispatch } from "react-redux";

// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
let Token = localStorage.getItem("cooljwt");
let decoded = jwt.decode(Token);
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);
const Check = require("is-null-empty-or-undefined").Check;




export default function Review_Approval(props) {

  // calculateMd5(file, (hash, err) => {
  //   if (hash) {
  //     console.log(hash);
  //   }
  // });


    // register form
    const classes = useStyles();
    const sweetClass = sweetAlertStyle();
    const [isLoading, setIsLoading] = React.useState(true);
    const [isFileSame, setIsFileSame] = React.useState(false);
    const [byEmail, setByEmail] = React.useState(false);
    const [byLoginName, setByLoginName] = React.useState(false);
    const [isSendingFile, setIsSendingFile] = React.useState(false);
    const [alert, setAlert] = React.useState(null);
    const dispatch = useDispatch();

    const warningAlert = (msg) => {
      setAlert(
        <SweetAlert
        warning
        style={{ display: "block", marginTop: "-100px" }}
        title="Warning!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={
            sweetClass.button + " " + sweetClass.warning
        }
        >
         {msg}
        </SweetAlert>
      );
    };
    const successAlert = (msg) => {
      setAlert(
        <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={
            sweetClass.button + " " + sweetClass.success
        }
        >
         {msg}
        </SweetAlert>
      );
    };
    const errorAlert = (msg) => {
    setAlert(
    <SweetAlert
    error
    style={{ display: "block", marginTop: "-100px" }}
    title="Error!"
    onConfirm={() => hideAlert()}
    onCancel={() => hideAlert()}
    confirmBtnCssClass={
        sweetClass.button + " " + sweetClass.danger
    }
    >
    {msg}
    <br />
    For Details Please Contact {process.env.REACT_APP_LDOCS_FOOTER_COPYRIGHT_LEVEL_1}
    </SweetAlert>
    );
    };
    const hideAlert = () => {
        setAlert(null);
    };
    const [formState, setFormState] = React.useState({
      userDetails: null,
      fileAuthDetails: null,
        values: {
        userId: "",
        referrenceTicket: "",
        reviewerTitle: "",
        },
        errors: {
        userId: "",
        referrenceTicket: "",
        reviewerTitle: "",
        },
    });
    const handleChange = (event) => {
        event.persist();
        setFormState((formState) => ({
            ...formState,
            userDetails: null,
            values: {
            ...formState.values,
            [event.target.name]: event.target.value,
            },
        }));
    };
   
    const setShareByLoginName = (event) => {
        setByLoginName(true);
        setByEmail(false);
    }
    const setShareByEmail = (event) => {
        setByLoginName(false);
        setByEmail(true);
    }
  const [validating, setValidating] = React.useState("");
  const verifyEmail = (value) => {
    var emailRex = /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    if (emailRex.test(value)) {
      return true;
    }
    return false;
  };
    const searchUserID = (user) => {
      setValidating(true);
      let userId = "";
      
      if (user != "") {
        userId = user;
      } else {
        userId = formState.values.userId;
        
      }
      let url;
      if (byLoginName && user == "") {
        if (verifyEmail(formState.values.userId)) {
          setFormState((formState) => ({
            ...formState,
            userDetails: null,
            errors: {
              ...formState.errors,
              userId: "error",
            },
          }));
          setValidating(false);
          return false;
        } else {
          setFormState((formState) => ({
            ...formState,
            userDetails: null,
            errors: {
              ...formState.errors,
              userId: "success",
            },
          }));
          url = `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/userlist/${userId}`;
        }
      } else if (byEmail && user == "") {
        
        if (verifyEmail(formState.values.userId)) {
          url = `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/userlistbyemail/${userId}`;
          setFormState((formState) => ({
            ...formState,
            userDetails: null,
            errors: {
              ...formState.errors,
              userId: "success",
            },
          }));
        } else {
          setFormState((formState) => ({
            ...formState,
            userDetails: null,
            errors: {
              ...formState.errors,
              userId: "error",
            },
          }));
          setValidating(false);
          return false;
        }
      } else if (user == "") {
        setValidating(false);
        errorAlert("Please select option for send by loginName or by email");
        return false;
      } else {
        url = `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/userlist/${userId}`;
      }
      axios({
        method: "get",
        url: url,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          setFormState((formState) => ({
            ...formState,
            userDetails: response.data,
          }));
          setValidating(false);
          setIsLoading(false);
           if (user == "") {
             successAlert("User Validated");
           }
          
        })
        .catch((error) => {
          setValidating(false);
          errorAlert(
            typeof error.response != "undefined"
              ? error.response.data
              : error.message
          );
        });
    };
  React.useEffect(() => {
  convertUrlToImageData(`${process.env.REACT_APP_LDOCS_API_URL}/igobgftgsftp/${props.fileData.fileOwner}/${props.fileData.fileId}`).then((res)=>{
    console.log(res+'  Check  '+props.fileData.fileHash);
    if (res === props.fileData.fileHash ) {
      setIsFileSame(true);
    }else{
      setIsFileSame(false);
      dispatch(sendEventLog(props.fileData, {
        eventTitle:'File is Changed',
        eventDescription:'File is modified (Off_Chain.....)'
      }));

    }
  });
    getFileAuthData();
  },[]);
    const getFileAuthData = () => {
        setIsLoading(true);
         axios({
           method: "get",
           url: `${process.env.REACT_APP_LDOCS_API_URL}/review/returntitlesid`,
           headers: { cooljwt: Token },
         })
           .then((response) => {
             if (typeof response.data.Message == "undefined") {
               setFormState((formState) => ({
                 ...formState,
                 fileAuthDetails: response.data,
               }));
               let userId = "";
               if (props.type == "Review") {
                 userId = response.data.reviewer;
               } else if (props.type == "Approval") {
                 userId = response.data.approver;
               }
               searchUserID(userId);
             } else {
               errorAlert(response.data.Message);
             }
           })
           .catch((error) => {
             setIsLoading(false);
             console.log(
               typeof error.response != "undefined"
                 ? error.response.data
                 : error.message
             );
             errorAlert(
               typeof error.response != "undefined"
                 ? error.response.data
                 : error.message
             );
           });
  };
  const sendForReview = () => {
    setIsSendingFile(true);
    let expiry = formState.fileAuthDetails.reviewExpirey;
    
    let reviewer = formState.userDetails.level3.loginName;

    let data = {
      fileName: props.fileData.fileName,
      fileId: props.fileData.fileId,
      fileHash: props.fileData.fileHash,
      filePath: props.fileData.filePath,
      fileType: props.fileData.fileType,
      fileOwner: props.fileData.fileOwner,
      expireyHours: expiry,
      reviewedBy: reviewer,
    };
    axios({
      method: "post",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/review/reviewrequest`,
      data: data,
      headers: { cooljwt: Token },
    })
      .then((response) => {
        console.log(response.data);
        if (typeof response.data.status == "undefined") {
          warningAlert(response.data);
        } else {
          successAlert("File sent for review");
          dispatch(sendNotification(`${data.fileId} File is sent for Review`, reviewer));
          dispatch(sendNotification(`${data.fileId} File is sent for Review`, data.fileOwner));
          dispatch(getNotification());
        }
        setIsSendingFile(false);
      })
      .catch((error) => {
        setIsSendingFile(false);
        errorAlert(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
      });
  }




  const sendForApproval = () => {
    setIsSendingFile(true);
    let expiry = formState.fileAuthDetails.reviewExpirey;

    let approver = formState.userDetails.level3.loginName;

    let data = {
      fileName: props.fileData.fileName,
      fileId: props.fileData.fileId,
      fileHash: props.fileData.fileHash,
      filePath: props.fileData.filePath,
      fileType: props.fileData.fileType,
      fileOwner: props.fileData.fileOwner,
      expireyHours: expiry,
      approvedBy: approver,
    };
    axios({
      method: "post",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/approve/approverequest`,
      data: data,
      headers: { cooljwt: Token },
    })
      .then((response) => {
        console.log(response.data);
        if (typeof response.data.status == "undefined") {
          warningAlert(response.data);
        } else {
          successAlert("File sent for approval");
          dispatch(sendNotification(`${data.fileId} File is sent for Approve`, approver));
          dispatch(sendNotification(`${data.fileId} File is sent for Approve`, data.fileOwner));
          dispatch(getNotification());
        }
        setIsSendingFile(false);
      })
      .catch((error) => {
        setIsSendingFile(false);
        errorAlert(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
      });
  };
    return (
      <GridContainer>
        {alert}
        <GridItem xs={12} sm={12} md={12}>
          <Card>
            <CardHeader color="info" icon>
              <CardIcon color="info">
                <h4 className={classes.cardTitle}>
                  Send For {props.type}:{" "}
                  {props.fileData.fileName +
                    " Version: " +
                    props.fileData.version}
                </h4>
              </CardIcon>
            </CardHeader>
            <CardBody>
              <GridContainer>
                {isLoading ? (
                  <CircularProgress disableShrink />
                ) : props.type == "Review" &&
                  formState.fileAuthDetails != null &&
                  formState.fileAuthDetails.overridereviewer == "true" ? (
                  <React.Fragment>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={8}
                      lg={8}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <TextField
                        fullWidth={true}
                        error={formState.errors.userId === "error"}
                        helperText={
                          formState.errors.userId === "error"
                            ? byEmail ? "Valid Email is required" : "Valid ID is required"
                            : null
                        }
                        label={byEmail ? "Enter Email":"Enter ID"}
                        id="userId"
                        name="userId"
                        onChange={(event) => {
                          handleChange(event);
                        }}
                        type="text"
                        value={formState.values.userId || ""}
                      />
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={4}
                      lg={4}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <Button
                        color="rose"
                        className={classes.registerButton}
                        round
                        type="button"
                        disabled={Check(formState.values.userId) ? true : false}
                        onClick={()=>searchUserID("")}
                      >
                        Validate
                      </Button>
                      {validating ? <CircularProgress disableShrink /> : ""}
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <FormControlLabel
                        control={
                          <Switch
                            checked={byLoginName}
                            onChange={(event) => setShareByLoginName(event)}
                            value="loginName"
                            classes={{
                              switchBase: classes.switchBase,
                              checked: classes.switchChecked,
                              thumb: classes.switchIcon,
                              track: classes.switchBar,
                            }}
                          />
                        }
                        classes={{
                          label: classes.label,
                        }}
                        label="By LoginName"
                      />
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <FormControlLabel
                        control={
                          <Switch
                            checked={byEmail}
                            onChange={(event) => setShareByEmail(event)}
                            value="email"
                            classes={{
                              switchBase: classes.switchBase,
                              checked: classes.switchChecked,
                              thumb: classes.switchIcon,
                              track: classes.switchBar,
                            }}
                          />
                        }
                        classes={{
                          label: classes.label,
                        }}
                        label="By Email"
                      />
                    </GridItem>
                  </React.Fragment>
                ) : props.type == "Approval" &&
                  formState.fileAuthDetails != null &&
                  formState.fileAuthDetails.overrideapprover == "true" ? (
                  <React.Fragment>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={8}
                      lg={8}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <TextField
                        fullWidth={true}
                        error={formState.errors.userId === "error"}
                        helperText={
                          formState.errors.userId === "error"
                            ? "Valid ID is required"
                            : null
                        }
                        label="Enter ID"
                        id="userId"
                        name="userId"
                        onChange={(event) => {
                          handleChange(event);
                        }}
                        type="text"
                        value={formState.values.userId || ""}
                      />
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={4}
                      lg={4}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <Button
                        color="rose"
                        className={classes.registerButton}
                        round
                        type="button"
                        disabled={Check(formState.values.userId) ? true : false}
                        onClick={()=>searchUserID("")}
                      >
                        Validate
                      </Button>
                      {validating ? <CircularProgress disableShrink /> : ""}
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <FormControlLabel
                        control={
                          <Switch
                            checked={byLoginName}
                            onChange={(event) => setShareByLoginName(event)}
                            value="loginName"
                            classes={{
                              switchBase: classes.switchBase,
                              checked: classes.switchChecked,
                              thumb: classes.switchIcon,
                              track: classes.switchBar,
                            }}
                          />
                        }
                        classes={{
                          label: classes.label,
                        }}
                        label="By LoginName"
                      />
                    </GridItem>
                    <GridItem
                      xs={12}
                      sm={12}
                      md={6}
                      lg={6}
                      style={{
                        marginTop: "10px",
                        marginBottom: "10px",
                      }}
                    >
                      <FormControlLabel
                        control={
                          <Switch
                            checked={byEmail}
                            onChange={(event) => setShareByEmail(event)}
                            value="email"
                            classes={{
                              switchBase: classes.switchBase,
                              checked: classes.switchChecked,
                              thumb: classes.switchIcon,
                              track: classes.switchBar,
                            }}
                          />
                        }
                        classes={{
                          label: classes.label,
                        }}
                        label="By Email"
                      />
                    </GridItem>
                  </React.Fragment>
                ) : (
                  ""
                )}
              </GridContainer>
              {formState.userDetails != null ? (
                <GridContainer>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{
                      marginTop: "10px",
                      marginBottom: "10px",
                    }}
                  >
                    <legend>User Image</legend>
                    <div className="fileinput text-center">
                      <div className="thumbnail img-circle">
                        <img
                          src={`data:${formState.userDetails.level1.profileImgT};base64,${formState.userDetails.level1.profileImg}`}
                          alt={formState.userDetails.level3.loginName}
                        />
                      </div>
                    </div>
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{
                      marginTop: "10px",
                      marginBottom: "10px",
                    }}
                  >
                    <TextField
                      fullWidth={true}
                      label="Login Name"
                      id="loginName"
                      name="loginName"
                      type="text"
                      value={formState.userDetails.level3.loginName || ""}
                      disabled={true}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{
                      marginTop: "10px",
                      marginBottom: "10px",
                    }}
                  >
                    <TextField
                      fullWidth={true}
                      label="Email"
                      id="email"
                      name="email"
                      type="text"
                      value={formState.userDetails.level3.email || ""}
                      disabled={true}
                    />
                  </GridItem>
                  <GridItem
                    xs={12}
                    sm={12}
                    md={4}
                    lg={4}
                    style={{
                      marginTop: "10px",
                      marginBottom: "10px",
                    }}
                  >
                    {!isFileSame ?
                     <List style={{width:500}}>
                        <ListItem>
                          <ListItemAvatar>
                                  <Button
                                      justIcon
                                      round
                                      simple
                                      icon={WarningIcon}
                                      color="danger"
                                      className="Edit"
                                    >
                            <WarningIcon />
                          </Button>
                          </ListItemAvatar>
                          <ListItemText primary="File has been modified (Off-Chain)"/>
                        </ListItem>
                      </List>
                      :''}
                  </GridItem>
                </GridContainer>
              ) : (
                ""
              )}
              <span style={{ float: "right" }}>
                {formState.userDetails != null ? (
                  <React.Fragment>
                    <Button
                      color="info"
                      className={classes.registerButton}
                      round
                      type="button"
                      onClick={
                        props.type == "Review" ? sendForReview : sendForApproval
                      }
                    >
                      Send For {props.type}
                    </Button>
                    {isSendingFile ? <CircularProgress disableShrink /> : ""}
                  </React.Fragment>
                ) : (
                  ""
                )}
                <Button
                  color="danger"
                  className={classes.registerButton}
                  onClick={props.closeModal}
                  round
                >
                  Close
                </Button>
              </span>
            </CardBody>
          </Card>
        </GridItem>
      </GridContainer>
    );
}
