/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  TextField,
  MenuItem,
  makeStyles,
  CircularProgress,
} from "@material-ui/core";
import SweetAlert from "react-bootstrap-sweetalert";
import { useDispatch } from "react-redux";
import { getDepartments } from "actions";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import axios from "axios";

// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function Register(props) {
  // register form
  const dispatch = useDispatch();
  const [formState, setFormState] = useState({
    orgs: [],
    comp: [],
    isRegistering: false,
    values: {
      departmentName: "",
      referenceTicket: "",
      titleHead: "",
      organizationName: "",
      companyName: "",
    },
    errors: {
      departmentName: "",
      referenceTicket: "",
      titleHead: "",
      organizationName: "",
      companyName: "",
    },
  });
    const getCompanies = () => {
      axios
        .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/comlistwoi`)
        .then((response) => {
          setFormState((formState) => ({
            ...formState,
            comp: response.data,
          }));
        })
        .catch((error) => {
          console.log("Unable to get Companies please contact at contact@avantas.io")
        });
    };
   const getOrganizations = () => {
     axios
       .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/orglistwoi`)
       .then((response) => {
         setFormState((formState) => ({
           ...formState,
           orgs: response.data,
         }));
       })
       .catch((error) => {
        console.log("Unable to get Organizations please contact at contact@avantas.io")
       });
   };
    useEffect(() => {
      getCompanies();
      getOrganizations();
    }, []);
  const handleChange = (event) => {
    event.persist();
    if (event.target.name == "organizationName") {
      setFormState((formState) => ({
        ...formState,
        values: {
          ...formState.values,
          companyName: "",
        },
      }));
    }
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
  const classes = useStyles();
  const sweetClass = sweetAlertStyle();
  const [alert, setAlert] = React.useState(null);
  const successAlert = (msg) => {
    setAlert(
      <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
      >
        {msg}
      </SweetAlert>
    );
  };
  const errorAlert = (msg) => {
    setAlert(
      <SweetAlert
        error
        style={{ display: "block", marginTop: "-100px" }}
        title="Error!"
        onConfirm={() => hideErrorAlert()}
        onCancel={() => hideErrorAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
      >
        {msg}
        <br />
        Unable To Register Department Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
      </SweetAlert>
    );
  };
 const hideAlert = () => {
   closeModal();
   setAlert(null);
 };
 const hideErrorAlert = () => {
   setAlert(null);
 };
  const handleRegister = () => {
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let departmentName;
      let referenceTicket;
      let titleHead;
      let organizationName;
      let companyName;
    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;

    if (!Check(formState.values.departmentName)) {
      departmentName = "success";
    } else {
      departmentName = "error";
      error = true;
    }
    if (!Check(formState.values.referenceTicket)) {
      referenceTicket = "success";
    } else {
      referenceTicket = "error";
      error = true;
    }
    if (!Check(formState.values.titleHead)) {
      titleHead = "success";
    } else {
      titleHead = "error";
      error = true;
    }
    if (!Check(formState.values.organizationName)) {
      organizationName = "success";
    } else {
      organizationName = "error";
      error = true;
    }
    if (!Check(formState.values.companyName)) {
      companyName = "success";
    } else {
      companyName = "error";
      error = true;
    }
    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        departmentName:departmentName,
        referenceTicket:referenceTicket,
        titleHead:titleHead,
        organizationName:organizationName,
        companyName:companyName,
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isRegistering: false,
        message: "Invalid User Details!",
      }));
      return false;
    } else {
      let data = {
        organizationName: formState.values.organizationName,
        companyName: formState.values.companyName,
        departmentName: formState.values.departmentName,
        titleHead: formState.values.titleHead,
        referenceTicket: formState.values.referenceTicket,
      };
      let msg = "";
      axios({
        method: "post",
        url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/regdep`,
        data: data,
      })
        .then((response) => {
          dispatch(getDepartments());
          props.getDepartments();
          setFormState((formState) => ({
            ...formState,
            message: "Department has been successfully registered!",
            isRegistering: false,
          }));
          msg = "Department Registered Successfully!";
          successAlert(msg);
        })
        .catch((error) => {
          setFormState((formState) => ({
            ...formState,
            message:
              typeof error.response != "undefined"
                ? error.response.data
                : error.message,
            isRegistering: false,
          }));
          msg =
            typeof error.response != "undefined"
              ? error.response.data
              : error.message;
          errorAlert(msg);
        });
    }
  };
  const closeModal = () => {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        departmentName: "",
        referenceTicket: "",
        titleHead: "",
        organizationName: "",
        companyName: "",
      },
      errors: {
        ...formState.errors,
        departmentName: "",
        referenceTicket: "",
        titleHead: "",
        organizationName: "",
        companyName: "",
      },
    }));
    props.closeModal();
  };
  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Add Department</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <form>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.departmentName === "error"}
                    helperText={
                      formState.errors.departmentName === "error"
                        ? "Valid Department Name is required"
                        : null
                    }
                    label="Department Name"
                    id="departmentName"
                    name="departmentName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.departmentName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.referenceTicket === "error"}
                    helperText={
                      formState.errors.referenceTicket === "error"
                        ? "Valid Referencet Ticket is required"
                        : null
                    }
                    label="Referencet Ticket"
                    id="referenceTicket"
                    name="referenceTicket"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.referenceTicket || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.titleHead === "error"}
                    helperText={
                      formState.errors.titleHead === "error"
                        ? "Valid Title is required"
                        : null
                    }
                    label="Title"
                    id="titleHead"
                    name="titleHead"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.titleHead || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.organizationName === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.organizationName === "error"
                        ? "Organization name is required"
                        : null
                    }
                    label="Organization Name"
                    name="organizationName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.organizationName || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Organization
                    </MenuItem>
                    {formState.orgs.map((org, index) => {
                      return (
                        <MenuItem
                          key={index}
                          value={org.organizationName.toUpperCase()}
                        >
                          {org.organizationName.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={6}
                  lg={6}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.companyName === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.companyName === "error"
                        ? "Company name is required"
                        : null
                    }
                    label="Company Name"
                    name="companyName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.companyName || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Company
                    </MenuItem>
                    {formState.comp.map((com, index) => {
                      return (
                        formState.values.organizationName == com.organizationName ? 
                        <MenuItem
                          key={index}
                          value={com.companyName.toUpperCase()}
                        >
                          {com.companyName.toUpperCase()}
                          </MenuItem>
                          : ""
                      );
                    })}
                  </TextField>
                </GridItem>
              </GridContainer>
              <Button
                color="info"
                className={classes.registerButton}
                round
                onClick={handleRegister}
              >
                Register
              </Button>
              {formState.isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </form>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
