/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  TextField,
  MenuItem,
  makeStyles,
  CircularProgress,
} from "@material-ui/core";
import SweetAlert from "react-bootstrap-sweetalert";
import { useDispatch } from "react-redux";
import { getTeam } from "actions";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import axios from "axios";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

import MultipleSelect from './MultiSelect';

const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function Register(props) {
  // register form
  var Token = localStorage.getItem("cooljwt");

  const dispatch = useDispatch();
  const [formState, setFormState] = useState({
    orgs: [],
    comp: [],
    depts: [],
    selectedWorkFlows:[],
    workFlows:[],
    isRegistering: false,
    values: {
      teamName: "",
      referenceTicket: "",
      titleHead: "",
      organizationName: "",
      companyName: "",
      departmentName: "",
    },
    errors: {
      teamName: "",
      referenceTicket: "",
      titleHead: "",
      organizationName: "",
      companyName: "",
      departmentName: "",
    },
  });
  const setWorkFlows = (x) => {
    setFormState((formState) => ({
      ...formState,
      selectedWorkFlows: x
    }));
    }
  const getWorkFlows = (org) => {
    return new Promise((res, rej)=>{
      axios({
        method: "get",
        url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/getworkflowbyorganization/${org}`,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          setFormState((formState) => ({
            ...formState,
            workFlows: response.data,
          }));
        })
    })     
  }
      const getCompanies = () => {
        axios
          .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/comlistwoi`)
          .then((response) => {
            setFormState((formState) => ({
              ...formState,
              comp: response.data,
            }));
          })
          .catch((error) => {
            setFormState((formState) => ({
              ...formState,
              isError: true,
              message:
                "Unable to get Departments please contact at contact@avantas.io", //typeof error.response != "undefined"  ? error.response.data : error.message
            }));
          });
      };
      const getOrganizations = () => {
        axios
          .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/orglistwoi`)
          .then((response) => {
            setFormState((formState) => ({
              ...formState,
              orgs: response.data,
            }));
          })
          .catch((error) => {
            setFormState((formState) => ({
              ...formState,
              isError: true,
              message:
                "Unable to get Departments please contact at contact@avantas.io", //typeof error.response != "undefined"  ? error.response.data : error.message
            }));
          });
        };
        const getDepartments = () => {
          axios
            .get(`${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/deplist`)
            .then((response) => {
              setFormState((formState) => ({
                ...formState,
                depts: response.data,
              }));
            })
            .catch((error) => {
              setFormState((formState) => ({
                ...formState,
                isError: true,
                message:
                  "Unable to get Departments please contact at contact@avantas.io", //typeof error.response != "undefined"  ? error.response.data : error.message
              }));
            });
        };
      useEffect(() => {
        getCompanies();
        getOrganizations();
        getDepartments();
      }, []);
  const handleChange = (event) => {
    event.persist();
     if (event.target.name == "organizationName") {
       setFormState((formState) => ({
         ...formState,
         values: {
           ...formState.values,
           companyName: "",
           departmentName: "",
           workFlows:""
         },
       }));
       getWorkFlows(event.target.value.toUpperCase()).then(()=>console.log('Loaded Data'));
     } else if (event.target.name == "companyName") {
        setFormState((formState) => ({
          ...formState,
          values: {
            ...formState.values,
            departmentName: "",
          },
        }));
            }
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
    const classes = useStyles();
    const sweetClass = sweetAlertStyle();
    const [alert, setAlert] = React.useState(null);
    const successAlert = (msg) => {
      setAlert(
        <SweetAlert
          success
          style={{ display: "block", marginTop: "-100px" }}
          title="Success!"
          onConfirm={() => hideAlert()}
          onCancel={() => hideAlert()}
          confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
        >
          {msg}
        </SweetAlert>
      );
    };
    const errorAlert = (msg) => {
      setAlert(
        <SweetAlert
          error
          style={{ display: "block", marginTop: "-100px" }}
          title="Error!"
          onConfirm={() => hideErrorAlert()}
          onCancel={() => hideErrorAlert()}
          confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
        >
          {msg}
          <br />
          Unable To Register Team Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
        </SweetAlert>
      );
    };
  const hideAlert = () => {
    closeModal();
    setAlert(null);
  };
  const hideErrorAlert = () => {
    setAlert(null);
  };
    const handleRegister = () => {
      setFormState((formState) => ({
        ...formState,
        isRegistering: true,
      }));
      let teamName;
      let referenceTicket;
      let titleHead;
      let organizationName;
      let companyName;
      let departmentName;
      const Check = require("is-null-empty-or-undefined").Check;
      var error = false;

      if (!Check(formState.values.teamName)) {
        teamName = "success";
      } else {
        teamName = "error";
        error = true;
      }
      if (!Check(formState.values.departmentName)) {
        departmentName = "success";
      } else {
        departmentName = "error";
        error = true;
      }
      if (!Check(formState.values.referenceTicket)) {
        referenceTicket = "success";
      } else {
        referenceTicket = "error";
        error = true;
      }
      if (!Check(formState.values.titleHead)) {
        titleHead = "success";
      } else {
        titleHead = "error";
        error = true;
      }
      if (!Check(formState.values.organizationName)) {
        organizationName = "success";
      } else {
        organizationName = "error";
        error = true;
      }
      if (!Check(formState.values.companyName)) {
        companyName = "success";
      } else {
        companyName = "error";
        error = true;
      }
      setFormState((formState) => ({
        ...formState,
        errors: {
          ...formState.errors,
          teamName:teamName,
          departmentName: departmentName,
          referenceTicket: referenceTicket,
          titleHead: titleHead,
          organizationName: organizationName,
          companyName: companyName,
        },
      }));
      if (error) {
        setFormState((formState) => ({
          ...formState,
          isRegistering: false,
          message: "Invalid Team Details!",
        }));
        return false;
      } else {
        let data = {
          teamName: formState.values.teamName,
          organizationName: formState.values.organizationName,
          companyName: formState.values.companyName,
          departmentName: formState.values.departmentName,
          titleHead: formState.values.titleHead,
          referenceTicket: formState.values.referenceTicket,
          workFlows:formState.selectedWorkFlows
        };
        let msg = "";
        axios({
          method: "post",
          url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/regtea`,
          data: data,
        })
          .then((response) => {
            dispatch(getTeam());
            props.getTeams();
            setFormState((formState) => ({
              ...formState,
              message: "Team has been successfully registered!",
              isRegistering: false,
            }));
            msg = "Team Registered Successfully!";
            successAlert(msg);
          })
          .catch((error) => {
            setFormState((formState) => ({
              ...formState,
              message:
                typeof error.response != "undefined"
                  ? error.response.data
                  : error.message,
              isRegistering: false,
            }));
            msg =
              typeof error.response != "undefined"
                ? error.response.data
                : error.message;
            errorAlert(msg);
          });
        console.log(data);
      }
    };
    const closeModal = () => {
      setFormState((formState) => ({
        ...formState,
        values: {
          ...formState.values,
          teamName: "",
          referenceTicket: "",
          titleHead: "",
          organizationName: "",
          companyName: "",
          departmentName: "",
        },
        errors: {
          ...formState.errors,
          teamName: "",
          referenceTicket: "",
          titleHead: "",
          organizationName: "",
          companyName: "",
          departmentName: "",
        },
      }));
      props.closeModal();
    };
  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>Add Team</h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <form>
              <GridContainer>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.teamName === "error"}
                    helperText={
                      formState.errors.teamName === "error"
                        ? "Valid Team Name is required"
                        : null
                    }
                    label="Team Name"
                    id="teamName"
                    name="teamName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.teamName || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.referenceTicket === "error"}
                    helperText={
                      formState.errors.referenceTicket === "error"
                        ? "Valid Reference Ticket is required"
                        : null
                    }
                    label="Reference Ticket"
                    id="referenceTicket"
                    name="referenceTicket"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.referenceTicket || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    fullWidth={true}
                    error={formState.errors.titleHead === "error"}
                    helperText={
                      formState.errors.titleHead === "error"
                        ? "Valid Title Head is required"
                        : null
                    }
                    label="Title Head"
                    id="titleHead"
                    name="titleHead"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    type="text"
                    value={formState.values.titleHead || ""}
                  />
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.organizationName === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.organizationName === "error"
                        ? "Organization name is required"
                        : null
                    }
                    label="Organization Name"
                    name="organizationName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.organizationName || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Organization
                    </MenuItem>
                    {formState.orgs.map((org, index) => {
                      return (
                        <MenuItem
                          key={index}
                          value={org.organizationName.toUpperCase()}
                        >
                          {org.organizationName.toUpperCase()}
                        </MenuItem>
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.companyName === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.companyName === "error"
                        ? "Company name is required"
                        : null
                    }
                    label="Company Name"
                    name="companyName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.companyName || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Company
                    </MenuItem>
                    {formState.comp.map((com, index) => {
                      return (
                        formState.values.organizationName == com.organizationName ? 
                        <MenuItem
                          key={index}
                          value={com.companyName.toUpperCase()}
                        >
                          {com.companyName.toUpperCase()}
                          </MenuItem>
                          :""
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={4}
                  lg={4}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <TextField
                    className={classes.textField}
                    error={formState.errors.departmentName === "error"}
                    fullWidth={true}
                    helperText={
                      formState.errors.departmentName === "error"
                        ? "Department name is required"
                        : null
                    }
                    label="Department Name"
                    name="departmentName"
                    onChange={(event) => {
                      handleChange(event);
                    }}
                    select
                    value={formState.values.departmentName || ""}
                  >
                    <MenuItem
                      disabled
                      classes={{
                        root: classes.selectMenuItem,
                      }}
                    >
                      Choose Department
                    </MenuItem>
                    {formState.depts.map((dep, index) => {
                      return formState.values.organizationName ==
                        dep.organizationName &&
                        formState.values.companyName == dep.companyName ? (
                        <MenuItem
                          key={index}
                          value={dep.departmentName.toUpperCase()}
                        >
                          {dep.departmentName.toUpperCase()}
                        </MenuItem>
                      ) : (
                        ""
                      );
                    })}
                  </TextField>
                </GridItem>
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "10px", marginBottom: "10px" }}
                >
                  <MultipleSelect workFlows={formState.workFlows} onChange={setWorkFlows} />
                </GridItem>
              </GridContainer>

              <Button
                color="info"
                className={classes.registerButton}
                round
                onClick={handleRegister}
              >
                Register
              </Button>
              {formState.isRegistering ? (
                <CircularProgress disableShrink />
              ) : (
                ""
              )}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </form>
          </CardBody>
        </Card>
      </GridItem>
    </GridContainer>
  );
}
