/*eslint-disable*/
import React, { useState, useEffect } from "react";
// @material-ui/core components
import {
  MenuItem,
  makeStyles,
  CircularProgress,
  LinearProgress,
  TextField,
  Input,
  InputAdornment,
} from "@material-ui/core";
// core components
import MessageIcon from "@material-ui/icons/Message";
// For Chips
import Avatar from "@material-ui/core/Avatar";
import Chip from "@material-ui/core/Chip";
import FaceIcon from "@material-ui/icons/Face";
import DoneIcon from "@material-ui/icons/Done";
import defaultAvatar from "assets/img/avatar-2.png";
import CardTravel from "@material-ui/icons/CardTravel";
import Timeline from "./TagsTimeline.js";


import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardIcon from "components/Card/CardIcon.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
import ChipInput from "material-ui-chip-input";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
let Token = localStorage.getItem("cooljwt");
let decoded = jwt.decode(Token);
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function FileTags(props) {
  // register form

  const classes = useStyles();
    const sweetClass = sweetAlertStyle();
  const [isSavingTags, setIsSavingTags] = React.useState(false);
  const [isLoading, setIsLoading] = React.useState(true);
  const [widgetStories, setWidgetStories] = React.useState([]);
  const [otherTags, setOtherTags] = React.useState([]);
  const [alert, setAlert] = React.useState(null);
  const successAlert = (msg) => {
    setAlert(
      <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
      >
        {msg}
      </SweetAlert>
    );
  };
  const errorAlert = (msg) => {
    setAlert(
      <SweetAlert
        error
        style={{ display: "block", marginTop: "-100px" }}
        title="Error!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
      >
        {msg}
        <br />
        For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
      </SweetAlert>
    );
  };
  const hideAlert = () => {
    setAlert(null);
  };
  const saveTags = () => {
    setIsSavingTags(true);
    let file = props.fileData;
    let result = []
    if (file.fileTags.length > 0) {
      var check =
        file.fileTags.filter((itm) => itm.loginName == decoded.loginName)
          .length > 0;
      if (check) {
        result = file.fileTags.map((itm) => {
          return itm.loginName != decoded.loginName
            ? { loginName: itm.loginName, tag: itm.tag }
            : { loginName: itm.loginName, tag: myChips };
        });
      } else {
        result = file.fileTags;
        result.push({ loginName: decoded.loginName, tag: myChips });
      }
      
    } else {
      result.push({ loginName: decoded.loginName, tag: myChips });
    }
    let data = {
      fileName: file.fileName,
      fileId: file.fileId,
      fileHash: file.fileHash,
      tags: result,
    };
     axios({
       method: "PATCH", 
       url: `${process.env.REACT_APP_LDOCS_API_URL}/file/updatetags`,
       data: data,
       headers: {
         cooljwt: Token,
       },
     })
       .then((response) => {
         successAlert(response.data);
         setIsSavingTags(false);
       })
       .catch((error) => {
         console.log(
           typeof error.response != "undefined"
             ? error.response.data
             : error.message
         );
         errorAlert(
           typeof error.response != "undefined"
             ? error.response.data
             : error.message
         );
         setIsSavingTags(false);
       });
   };
  const getFileTags = () => {
    
    let decoded = jwt.decode(Token);
    let file = props.fileData;
    let data = {
      fileName: file.fileName,
      fileId: file.fileId,
      fileHash: file.fileHash,
      tagger: decoded.loginName,
      fileOwner: file.fileOwner,
    };
    axios({
      method: "POST", //you can set what request you want to be
      url: `${process.env.REACT_APP_LDOCS_API_URL}/file/gettags`,
      data: data,
      headers: {
        cooljwt: Token,
      },
    })
      .then((response) => {

        if (response.data.length > 0 && typeof response.data != 'string') {
          let tags = response.data.filter(
            (itm) => itm.loginName != decoded.loginName
          );
          setTimeline(tags);
          let result = response.data.filter(
            (itm) => itm.loginName == decoded.loginName
          );
          if (result.length > 0) {
            result = result.map((itm) => {
              return itm.tag;
            });
            setMyChips(result[0]);
          }
        }else{
          setMyChips([]);
        }
        setIsLoading(false);
      })
      .catch((error) => {
        console.log(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
        setIsLoading(false);
      });
  };
    React.useEffect(() => {
      getFileTags();
    }, []);
  
  const setTimeline = (tags) => {
    let timelineData = tags.map((item, index) => {
      let profileImage = defaultAvatar;
       if (item.img != "" || typeof item.img != "undefined") {
         var base64Flag = `data:${item.imgtype};base64,`;
         profileImage = base64Flag + item.img;
       }
      return {
        // First story
        inverted: true,
        badgeColor: "info",
        badgeIcon: profileImage,
        title: item.loginName,
        titleColor: "info",
        body: item.tag.map((tg, index) => {
          return (
              <Chip key={index} label={tg} />
          );
        }),
      };
    });
    setWidgetStories(timelineData);

  }
  const [myChips, setMyChips] = React.useState([]);
    const handleChips = (chip) => {
        let chips = myChips;
        let index = chip.length - 1;
        chips.push(chip[index]);
         setMyChips(chips);
  };
    const handleDeleteChip = (chip, index) => {
        let chips = myChips;
        chips.splice(index, 1);
        setMyChips(chips);
        document.getElementById("tagElementInput").focus();
    };
  function closeModal() {
    props.closeTagModal();
  }
  return (
    <GridContainer>
      {alert}
      <GridItem xs={12} sm={12} md={12}>
        <Card>
          <CardHeader color="info" icon>
            <CardIcon color="info">
              <h4 className={classes.cardTitle}>
                Add Tags For:{" "}
                {props.fileData.fileName +
                  " Version: " +
                  props.fileData.version}
              </h4>
            </CardIcon>
          </CardHeader>
          <CardBody>
            <GridContainer>
              <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={12}
                style={{ marginTop: "20px", marginBottom: "20px" }}
              >
                {isLoading ? (
                  // <CircularProgress disableShrink />
                  <LinearProgress />
                ) : (
                  <ChipInput
                    label="My Tags"
                    id="tagElementInput"
                    value={myChips}
                    onChange={(chips) => handleChips(chips)}
                    onDelete={(chip, index) => handleDeleteChip(chip, index)}
                  />
                )}
              </GridItem>
            </GridContainer>
            <span style={{ float: "right" }}>
              <Button
                color="info"
                className={classes.registerButton}
                round
                type="button"
                onClick={saveTags}
              >
                Save Tags
              </Button>
              {isSavingTags ? <CircularProgress disableShrink /> : ""}
              <Button
                color="danger"
                className={classes.registerButton}
                onClick={closeModal}
                round
              >
                Close
              </Button>
            </span>
          </CardBody>
        </Card>
        {isLoading ? (
          // <CircularProgress disableShrink />
          ""
        ) : widgetStories.length > 0 ? (
          <Card>
            <CardHeader color="info" icon>
              <CardIcon color="info">
                <h4 className={classes.cardTitle}>Tags List By Other Users</h4>
              </CardIcon>
            </CardHeader>
            <CardBody>
              <GridContainer>
                {/* isLoading otherTags */}
                <GridItem
                  xs={12}
                  sm={12}
                  md={12}
                  lg={12}
                  style={{ marginTop: "20px", marginBottom: "20px" }}
                >
                  <Timeline simple stories={widgetStories} />
                </GridItem>
              </GridContainer>
            </CardBody>
          </Card>
        ) : (
          ""
        )}
      </GridItem>
    </GridContainer>
  );
}
