import React, { useState, useEffect } from "react";
// @material-ui/icons
import {
  Button,
  makeStyles,
  CircularProgress,
  TextField,
  MenuItem,
  FormControlLabel,
  Checkbox
} from "@material-ui/core";
// @material-ui/core components
import Check from "@material-ui/icons/Check";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import { Animated } from "react-animated-css";
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";

var Token = localStorage.getItem("cooljwt");
const useStyles = makeStyles(styles);
const sweetAlertStyle = makeStyles(styles2);

export default function Step3(props) {
  const classes = useStyles();
  const [animateStep, setAnimateStep] = useState(true);
  var row = props.userData.level3;
  const [formState, setFormState] = useState({
    isLoading: false,
    values: {
      loginName: typeof row.loginName != "undefined" ? row.loginName : "",
      email: typeof row.email != "undefined" ? row.email : "",
      disabledRef: typeof row.disabledRef != "undefined" ? row.disabledRef : "",
      folderPath: typeof row.folderPath != "undefined" ? row.folderPath : "",
      workflow: typeof row.workflow != "undefined" ? row.workflow : "",
      disabledRefCheck: typeof row.disabledRef != "undefined" && row.disabledRef != null ? true : false,
    },
    errors: {},
  });
  const handleChange = (event) => {
    event.persist();

    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [event.target.name]: event.target.value.toUpperCase(),
      },
    }));
  };
  const sweetClass = sweetAlertStyle();
  const [alert, setAlert] = React.useState(null);
  const successAlert = (msg) => {
    setAlert(
      <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
      >
        {msg}
      </SweetAlert>
    );
  };
  const errorAlert = (msg) => {
    setAlert(
      <SweetAlert
        error
        style={{ display: "block", marginTop: "-100px" }}
        title="Error!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
      >
        {msg}
        <br />
        Unable To Update Level 3 Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
      </SweetAlert>
    );
  };
  const hideAlert = () => {
    setAlert(null);
  };
  const verifyEmail = (value) => {
    var emailRex = /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    if (emailRex.test(value)) {
      return true;
    }
    return false;
  };
  const saveUserLevelThree = () => {
    setFormState((formState) => ({
      ...formState,
      isLoading: true,
    }));
    let loginName;
    let email;
    let folderPath;
    let workflow;

    const Check = require("is-null-empty-or-undefined").Check;
    var error = false;

    if (!Check(formState.values.loginName)) {
      loginName = "success";
    } else {
      loginName = "error";
      error = true;
    }
    if (!Check(formState.values.folderPath) && formState.values.folderPath <= 100) {
      folderPath = "success";
    } else {
      folderPath = "error";
      error = true;
    }
    if (!Check(formState.values.workflow)) {
      workflow = "success";
    } else {
      workflow = "error";
      error = true;
    }
   if (!Check(formState.values.email)) {
     if (verifyEmail(formState.values.email)) {
       email = "success";
     } else {
       email = "error";
       error = true;
     }
   } else {
     email = "error";
     error = true;
   }
    setFormState((formState) => ({
      ...formState,
      errors: {
        ...formState.errors,
        loginName: loginName,
        email: email,
        folderPath: folderPath,
        workflow: workflow,
      },
    }));
    if (error) {
      setFormState((formState) => ({
        ...formState,
        isLoading: false,
      }));
      return false;
    } else {
      var data = {
        loginName: formState.values.loginName,
        email: formState.values.email,
        disabledRef: formState.values.disabledRef,
        folderPath: formState.values.folderPath,
        workflow: formState.values.workflow,
      };
      let msg = "";
      let Token = localStorage.getItem("cooljwt");

      axios({
        method: "post",
        url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/upd/avuserthree`,
        data: data,
        headers: { cooljwt: Token },
      })
        .then((response) => {
          props.userData.level3.loginName = data.loginName;
          props.userData.level3.email = data.email;
          props.userData.level3.disabledRef = data.disabledRef;
          props.userData.level3.folderPath = data.folderPath;
          props.userData.level3.workflow = data.workflow;
          props.updateUserData(props.userData);
          setFormState((formState) => ({
            ...formState,
            isLoading: false,
          }));
          msg = "Level 3 Info Updated Successfully!";
          successAlert(msg);
        })
        .catch((error) => {
          setFormState((formState) => ({
            ...formState,
            isLoading: false,
          }));
          msg =
            typeof error.response != "undefined"
              ? error.response.data
              : error.message;
          errorAlert(msg);
        });
    }
  };
  useEffect(() => {
    getMyWorkflows(props.userData.level2.organization);
  }, []);
  const [isLoading, setIsLoading] = React.useState(false);
  const [workflows, setWorkflows] = React.useState([]);
  const getMyWorkflows = (Org) => {
    setIsLoading(true);
    axios({
      method: "get",
      url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/getworkflowbyorganization/${Org}`,
      headers: { cooljwt: Token },
    })
      .then((response) => {
        setWorkflows(response.data);
        setIsLoading(false);
      })
      .catch((error) => {
        setWorkflows([]);
        console.log(
          typeof error.response != "undefined"
            ? error.response.data
            : error.message
        );
        setIsLoading(false);
      });
  };

  const handleToggle = (name) => {
    setFormState((formState) => ({
      ...formState,
      values: {
        ...formState.values,
        [name]: !formState.values.disabledRefCheck == false ? "" : new Date(),
        disabledRefCheck: !formState.values.disabledRefCheck
      },
    }));
}; 
  return (
    <Animated
      animationIn="bounceInRight"
      animationOut="bounceOutLeft"
      animationInDuration={1000}
      animationOutDuration={1000}
      isVisible={animateStep}
    >
      {alert}
      <GridContainer justify="center" md={12} md={12} xs={12} sm={12}>
        <GridItem
          xs={12}
          sm={12}
          md={6}
          lg={6}
          style={{ marginBottom: "10px", marginTop: "10px" }}
        >
          <TextField
            fullWidth={true}
            error={formState.errors.loginName === "error"}
            helperText={
              formState.errors.loginName === "error"
                ? "Valid Login Name is required"
                : null
            }
            label="User ID"
            id="loginName"
            name="loginName"
            onChange={(event) => {
              handleChange(event);
            }}
            type="text"
            disabled={props.disabledCheck}
            value={formState.values.loginName || ""}
          />
        </GridItem>
        <GridItem
          xs={12}
          sm={12}
          md={6}
          lg={6}
          style={{ marginBottom: "10px", marginTop: "10px" }}
        >
          <TextField
            className={classes.textField}
            error={formState.errors.email === "error"}
            fullWidth={true}
            helperText={
              formState.errors.email === "error" ? "email is required" : null
            }
            label="email"
            name="email"
            onChange={(event) => {
              handleChange(event);
            }}
            type="email"
            disabled={props.disabledCheck}
            value={formState.values.email || ""}
          ></TextField>
        </GridItem>
        <GridItem
          xs={12}
          sm={12}
          md={6}
          lg={6}
          style={{ marginBottom: "10px", marginTop: "10px" }}
        >
          <TextField
            fullWidth={true}
            error={formState.errors.folderPath === "error"}
            helperText={
              formState.errors.folderPath === "error"
                ? "Valid Storage Size is required"
                : null
            }
            label="Max Storage Size"
            id="folderPath"
            name="folderPath"
            onChange={(event) => {
              handleChange(event);
            }}
            type="number"
            disabled={props.disabledCheck}
            value={formState.values.folderPath || ""}
          />
        </GridItem>
        {/* Commented Code Due to WorkFlow Update */}
        {/* <GridItem
          xs={12}
          sm={12}
          md={6}
          lg={6}
          style={{ marginBottom: "10px", marginTop: "10px" }}
        >
          <TextField
            className={classes.textField}
            error={formState.errors.workflow === "error"}
            fullWidth={true}
            helperText={
              formState.errors.workflow === "error"
                ? "Workflow is required"
                : null
            }
            label="Workflow"
            name="workflow"
            onChange={(event) => {
              handleChange(event);
            }}
            select
            value={formState.values.workflow || ""}
            disabled={props.disabledCheck}
          >
            <MenuItem
              disabled
              classes={{
                root: classes.selectMenuItem,
              }}
            >
              Choose Workflow
            </MenuItem>
            {workflows.map((wf, index) => {
              return (
                <MenuItem key={index} value={wf.workflowName}>
                  {wf.workflowName}
                </MenuItem>
              );
            })}
          </TextField>
        </GridItem> */}
        <GridItem
          xs={12}
          sm={12}
          md={12}
          lg={12}
          style={{ marginBottom: "10px", marginTop: "10px" }}
        >
           <div
                        className={
                          classes.checkboxAndRadio +
                          " " +
                          classes.checkboxAndRadioHorizontal
                        }
                      >
                        <FormControlLabel
                          control={
                            <Checkbox
                              tabIndex={-1}
                              onClick={() => handleToggle("disabledRef")}
                              checked={formState.values.disabledRefCheck}
                              checkedIcon={
                                <Check className={classes.checkedIcon} />
                              }
                              icon={<Check className={classes.uncheckedIcon} />}
                              classes={{
                                checked: classes.checked,
                                root: classes.checkRoot,
                              }}
                              disabled={props.disabledCheck}
                            />
                          }
                          classes={{
                            label: classes.label,
                            root: classes.labelRoot,
                          }}
                          label="Disabled Ref"
                        />
                      </div>
        </GridItem>
        {props.disabledCheck ? (
          ""
        ) : (
          <GridItem
            xs={12}
            sm={12}
            md={12}
            lg={12}
            style={{
              marginBottom: "20px",
              marginTop: "20px",
            }}
          >
            <Button
              style={{
                backgroundColor: "#00AFC3",
                color: "white",
              }}
              className={classes.registerButton}
              round
              onClick={saveUserLevelThree}
            >
              Save Level 3 Info
            </Button>
            {formState.isLoading ? <CircularProgress disableShrink /> : ""}
          </GridItem>
        )}
      </GridContainer>
    </Animated>
  );
}
