import React, { useState, useEffect} from "react";
// react component for creating dynamic tables
import ReactTable from "react-table";

// @material-ui/core components
import { makeStyles } from "@material-ui/core/styles";
import CircularProgress from "@material-ui/core/CircularProgress";
import Slide from "@material-ui/core/Slide";
import Dialog from "@material-ui/core/Dialog";
import DialogContent from "@material-ui/core/DialogContent";
import Tooltip from "@material-ui/core/Tooltip";
// @material-ui/icons
import Edit from "@material-ui/icons/Edit";
import Close from "@material-ui/icons/Close";
import VisibilityIcon from "@material-ui/icons/Visibility";
// core components
import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Button from "components/CustomButtons/Button.js";
import Card from "components/Card/Card.js";
import CardBody from "components/Card/CardBody.js";
import CardIcon from "components/Card/CardIcon.js";
import CardHeader from "components/Card/CardHeader.js";
import RegisterUser from "./RegisterUser";

import { cardTitle } from "assets/jss/material-dashboard-pro-react.js";
import { Animated } from "react-animated-css";
import UpdateUser from "./UpdateUser";
import axios from "axios";

const styles = {
  cardIconTitle: {
    ...cardTitle,
    marginTop: "15px",
    marginBottom: "0px",
  },
  cardTitleText: {
    color: "white",
  },
  buttonRight: {},
};

const useStyles = makeStyles(styles);

const Transition = React.forwardRef(function Transition(props, ref) {
  return <Slide direction="down" ref={ref} {...props} />;
});

export default function UsersList() {
  const classes = useStyles();
  const [classicModal, setClassicModal] = useState(false);
  const [userData, setUserData] = useState(false);
  const [animateTable, setAnimateTable] = useState(true);
  const [animateTableView, setAnimateTableView] = useState(true);
  const [editComponent, setEditComponent] = useState(false);
  const [isLoading, setIsLoading] = React.useState(true);
  const [editComponentView, setEditComponentView] = useState(false);
  const editUser = (row) => {
    setDisabledCheck(false);
    setAnimateTable(false);
    setUserData(row)
    setTimeout(function () {
      setAnimateTableView(false);
      setEditComponentView(true);
      setEditComponent(true);
    }, 500);
   
  }
  const deleteUser = (row) => {
      setEditComponent(false);
    setTimeout(function () {
      setEditComponentView(false);
       setAnimateTableView(true);
      setAnimateTable(true);
    }, 500);
  }
  const [disabledCheck, setDisabledCheck] = useState(false);
  const viewUser = (row) => {
    setDisabledCheck(true);
     setAnimateTable(false);
     setUserData(row);
     setTimeout(function() {
       setAnimateTableView(false);
       setEditComponentView(true);
       setEditComponent(true);
     }, 500);
  }
  const [data, setData] = useState();
   useEffect(() => {
     getTeams();
   },[]);
  const getTeams = () => {
    let Token = localStorage.getItem("cooljwt");
         axios({
           method: "get",
           url: `${process.env.REACT_APP_LDOCS_API_URL}/dev/reg/userlistwoi`,
           headers: { cooljwt: Token },
         })
           .then((response) => {
             setData(
               response.data.map((prop, key) => {
                 return {
                   id: prop._id,
                   name: prop.level3.loginName,
                   title: prop.level2.title,
                   email: prop.level3.email,
                   organization: prop.level2.organization,
                   company: prop.level2.companyName,
                   department: prop.level2.department,
                   team: prop.level2.team,
                   actions: (
                     <div className="actions-right">
                       <Tooltip title="View User" aria-label="viewuser">
                         <Button
                           justIcon
                           round
                           simple
                           icon={VisibilityIcon}
                           onClick={() => viewUser(prop)}
                           color="warning"
                           className="View"
                         >
                           <VisibilityIcon />
                         </Button>
                       </Tooltip>
                       <Tooltip title="Edit User" aria-label="edituser">
                         <Button
                           justIcon
                           round
                           simple
                           icon={Edit}
                           onClick={() => editUser(prop)}
                           color="warning"
                           className="Edit"
                         >
                           <Edit />
                         </Button>
                       </Tooltip>
                       <Tooltip title="Delete User" aria-label="deleteuser">
                         <Button
                           justIcon
                           round
                           simple
                           onClick={() => deleteUser(prop)}
                           color="danger"
                           className="remove"
                         >
                           <Close />
                         </Button>
                       </Tooltip>
                     </div>
                   ),
                 };
               })
             );
             setIsLoading(false);
           })
           .catch((error) => {
             console.log(
               typeof error.response != "undefined"
                 ? error.response.data
                 : error.message
             );
             setIsLoading(false);
           });
  };
  const updateUserData = (userObject) =>{
    setUserData(userObject);
  }
  return (
    <div>
      <GridContainer justify="center">
        <GridItem xs={12} sm={12} md={12} className={classes.center}>
          <Dialog
            classes={{
              root: classes.center + " " + classes.modalRoot,
              paper: classes.modal,
            }}
            fullWidth={true}
            maxWidth={"md"}
            open={classicModal}
            TransitionComponent={Transition}
            keepMounted
            onClose={() => setClassicModal(false)}
            aria-labelledby="classic-modal-slide-title"
            aria-describedby="classic-modal-slide-description"
          >
            <DialogContent
              id="classic-modal-slide-description"
              className={classes.modalBody}
            >
              <RegisterUser
                closeModal={() => setClassicModal(false)}
                getTeams={getTeams}
              />
            </DialogContent>
          </Dialog>
        </GridItem>
      </GridContainer>
      {animateTableView ? (
        <Animated
          animationIn="bounceInRight"
          animationOut="bounceOutLeft"
          animationInDuration={1000}
          animationOutDuration={1000}
          isVisible={animateTable}
        >
          <GridContainer>
            <GridItem xs={12}>
              <Card>
                <CardHeader color="info" icon>
                  <CardIcon color="info">
                    <h4 className={classes.cardTitleText}>Users List</h4>
                  </CardIcon>
                  <Button
                    color="info"
                    round
                    style={{ float: "right" }}
                    className={classes.marginRight}
                    onClick={() => setClassicModal(true)}
                  >
                    Add New User
                  </Button>
                </CardHeader>
                <CardBody>
                  {isLoading ? (
                    <CircularProgress disableShrink />
                  ) : (
                    <ReactTable
                      data={data}
                      sortable={false}
                      columns={[
                        {
                          Header: "User ID",
                          accessor: "name",
                        },
                        {
                          Header: "Title",
                          accessor: "title",
                        },
                        {
                          Header: "Email",
                          accessor: "email",
                        },
                        {
                          Header: "Organization",
                          accessor: "organization",
                        },
                        {
                          Header: "Company",
                          accessor: "company",
                        },
                        {
                          Header: "Department",
                          accessor: "department",
                        },
                        {
                          Header: "Team",
                          accessor: "team",
                        },
                        {
                          Header: "Actions",
                          accessor: "actions",
                        },
                      ]}
                      defaultPageSize={10}
                      showPaginationTop
                      showPaginationBottom={true}
                      filterable={true}
                      className="-striped -highlight"
                    />
                  )}
                </CardBody>
              </Card>
            </GridItem>
          </GridContainer>
        </Animated>
      ) : (
        ""
      )}
      {editComponentView ? (
        <Animated
          animationIn="bounceInRight"
          animationOut="bounceOutLeft"
          animationInDuration={1000}
          animationOutDuration={1000}
          isVisible={editComponent}
        >
          <UpdateUser
            goBack={deleteUser}
            userData={userData}
            updateUserData={updateUserData}
            disabledCheck={disabledCheck}
          />
        </Animated>
      ) : (
        ""
      )}
    </div>
  );
}
