const createWorkflow = () => {
  
  let workflowName;
  let referrenceTicket;
  let organizationName;
  let companyName;

  const Check = require("is-null-empty-or-undefined").Check;
  var error = false;

  if (!Check(formState.values.workflowName)) {
    workflowName = "success";
  } else {
    workflowName = "error";
    error = true;
  }
  if (!Check(formState.values.organizationName)) {
    organizationName = "success";
  } else {
    organizationName = "error";
    error = true;
  }
  if (!Check(formState.values.companyName)) {
    companyName = "success";
  } else {
    companyName = "error";
    error = true;
  }
  if (!Check(formState.values.referrenceTicket)) {
    referrenceTicket = "success";
  }
  else {
    referrenceTicket = "error";
    error = true;
  }
  if (steps.length == 0){
    error = true;
  }
  setFormState((formState) => ({
    ...formState,
    errors: {
      ...formState.errors,
      workflowName: workflowName,
      referrenceTicket: referrenceTicket,
      organizationName: organizationName,
      companyName: companyName,
    },
  }));
  if (error) {
    setFormState((formState) => ({
      ...formState,
      isRegistering: false,
    }));
    steps.length != 0 ? 
    errorAlert("Invalid Details!") : 
    errorAlert("Please Add Steps .....");
    return false;
  } else {




  if(Updating){
      if(!OTP){
        setotpModal(true);
        return false;
      }
    }
    setFormState((formState) => ({
      ...formState,
      isRegistering: true,
    }));
    let decoded = jwt.decode(Token);
    const userName = decoded.loginName;
    let data = {
      workflowName:formState.values.workflowName,
      referenceTicket:formState.values.referrenceTicket,
      organizationName:formState.values.organizationName,
      organizationId:formState.values.organizationName,
      companyName:formState.values.companyName,
      companyId:formState.values.companyId,
      comments:formState.values.comments,
      created:new Date(Date.now()),
      createdBy:userName,
      IsActive:true,
      Steps :steps
    };


    let msg = "";
    let url = `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/createworkflow`;
    let method = "post";
    if(Updating){
      url = `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/updworkflow`;
      method = "patch";
      data.otp = OTP;
    }



    axios({
      method: method,
      url: url,
      data: data,
      headers: { cooljwt: Token },
    })
      .then((response) => {
        setOTP("");
        setIsLoading(false);
            msg = "Workflow Registered Successfully!";
          if(Updating){
            msg = "Workflow Updated Successfully!";
          }
          successAlert(msg); 
      })
      .catch((error) => {
        setOTP("");
        setIsLoading(false);
        msg =
          typeof error.response != "undefined"
            ? error.response.data
            : error.message;
        errorAlert(msg);
      });
  }
  };

