/*eslint-disable*/
import React, { useState, useEffect, forwardRef } from "react";
// @material-ui/core components
import {
  makeStyles,
  withStyles,
  Typography,
  Chip,
  Divider,
  LinearProgress
} from "@material-ui/core";
// core components

import GridContainer from "components/Grid/GridContainer.js";
import GridItem from "components/Grid/GridItem.js";
import Card from "components/Card/Card.js";
import CardHeader from "components/Card/CardHeader.js";
import CardBody from "components/Card/CardBody.js";
import SweetAlert from "react-bootstrap-sweetalert";
import axios from "axios";
import jwt from "jsonwebtoken";
// style for this view
import styles from "assets/jss/material-dashboard-pro-react/views/validationFormsStyle.js";
import styles2 from "assets/jss/material-dashboard-pro-react/views/sweetAlertStyle.js";
let Token = localStorage.getItem("cooljwt");
import QRCode from 'qrcode'
import {CopyToClipboard} from 'react-copy-to-clipboard';
import InputLabel from '@material-ui/core/InputLabel';
import MenuItem from '@material-ui/core/MenuItem';
import FormControl from '@material-ui/core/FormControl';
import Select from '@material-ui/core/Select';
import Stepper from '@material-ui/core/Stepper';
import Step from '@material-ui/core/Step';
import StepLabel from '@material-ui/core/StepLabel';
import StepContent from '@material-ui/core/StepContent';
import StepConnector from '@material-ui/core/StepConnector';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListSubheader from '@material-ui/core/ListSubheader';
import PerfectScrollbar from 'react-perfect-scrollbar';
import 'react-perfect-scrollbar/dist/css/styles.css';
import TableCell from '@material-ui/core/TableCell';
import TableRow from '@material-ui/core/TableRow';
import Table from '@material-ui/core/Table';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableBody from '@material-ui/core/TableBody';
import QueryBuilderIcon from '@material-ui/icons/QueryBuilder';
import CheckCircleIcon from '@material-ui/icons/CheckCircle';


let decoded = jwt.decode(Token);
const useStyle = makeStyles(styles);
const useStyles = makeStyles((theme) => ({
  root: {
    width: '100%',
    backgroundColor: theme.palette.background.paper,
    maxHeight: 500,
    position: 'relative',
    maxWidth: 360,
  },
  listSection: {
    backgroundColor: 'inherit',
  },
  ul: {
    backgroundColor: 'inherit',
    padding: 0,
  },
  table: {
    minWidth: '100%',
    border:1
  },
  TableCell:{
      width:'10%'
  },
  TableRow:{
      cursor:'pointer',
      background:'white',
      border:1, width:'100%'
  }
  
  }));
  
const sweetAlertStyle = makeStyles(styles2);

  const FileAdvanceView = forwardRef((props, ref) =>{
  // register form
  const classes = useStyle();
  const classesList = useStyles();
  const sweetClass = sweetAlertStyle();
  const [isLoading, setIsLoading] = useState(true);
  const [isCopied, setIsCopied] = useState(false);
  const [qrCode, setQrCode] = useState(null);
  const [blockChainData, setBlockChainData] = useState([]);
  const [shareWith, setShareWith] = useState([]);
  const [versions, setVersions] = useState([]);
  const [fileData, setFileData] = useState(props.fileData);
  const [version, setVersion] = useState(fileData.version);
  const [workflow, setWorkflow] = useState(null);
  const [isShared, setIsShared] = useState(false);
  

  
  const successAlert = (msg) => {
    setAlert(
      <SweetAlert
        success
        style={{ display: "block", marginTop: "-100px" }}
        title="Success!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.success}
      >
        {msg}
      </SweetAlert>
    );
  };
  const errorAlert = (msg) => {
    setAlert(
      <SweetAlert
        error
        style={{ display: "block", marginTop: "-100px" }}
        title="Error!"
        onConfirm={() => hideAlert()}
        onCancel={() => hideAlert()}
        confirmBtnCssClass={sweetClass.button + " " + sweetClass.danger}
      >
        {msg}
        <br />
        For Details Please Contact {process.env.REACT_APP_LDOCS_CONTACT_MAIL}
      </SweetAlert>
    );
  };
  const hideAlert = () => {
    setAlert(null);
  };

  const getBlockChainData = () => {
    return new Promise((res,rej)=>{
      axios({
        method: "get", //you can set what request you want to be
                url: `${process.env.REACT_APP_LDOCS_API_BOOKCHAIN_URL}/api/queryhistory/${fileData.fileId}`
        })
        .then((response) => {
          if(response.data.length !== 0){
          setBlockChainData(response.data);
          res(response.data);
        }})
        .catch((err)=>{
          console.log(err);
        })
    }) 
  }

  const getQrCode = () => {
    return new Promise((res,rej)=>{
      QRCode.toDataURL(fileData.fileId)
      .then(url => {
          setQrCode(url)
          res(url);
      })
      .catch(err => {
        console.error(err)
      });
    }) 
  }

  const Changehandler = (event) => {
    setIsLoading(true);
    let fileId = versions.find(item=> item.version == event.target.value).fileId;
    axios({
      method: "get", //you can set what request you want to be
          url: `${process.env.REACT_APP_LDOCS_API_URL}/files/getFileInfo/${fileId}`
      })
      .then((response) => {
        setFileData(response.data);
        setVersion(response.data.version);
      }).catch((err)=>{
        console.log(err);
        setIsLoading(false);
      })
    
  }


  const QontoConnector = withStyles({
    alternativeLabel: {
    top: 3,
    left: 'calc(-50% + 16px)',
    right: 'calc(50% + 16px)',
    },
    line: {
    borderColor: '#eaeaf0',
    borderTopWidth: 3,
    borderRadius: 1,
    },
  })(StepConnector);

  function getStepContent(stp, ind) {
    var step = JSON.parse(stp.Record);
    return (
      <Card  variant="outlined" 
        style={{ padding: "10px", marginTop:-5}}
      >
        <CardHeader>
        <Typography variant="subtitle2" component="h2">
                {step.event.toUpperCase()} STEP
        </Typography> 
        </CardHeader>
        <Divider />
        <CardBody>
        <GridContainer
        style={{ padding: "10px"}}
        >
          <GridItem
          xs={12}
          sm={12}
          md={8}
          lg={8}
          >
            <Typography variant="subtitle2" component="h2">
                  {step.eventFor.toUpperCase()}
            </Typography>
          </GridItem>
          <GridItem
          xs={12}
          sm={12}
          md={4}
          lg={4}
          >
            <Chip size="small" label={step.eventStatus.toUpperCase()} />
          </GridItem>
        </GridContainer>
        </CardBody>
        <Divider />
        <CardHeader 
        >
        <Typography variant="subtitle2" component="h2"
        style={{ padding: "10px"}}
        >
                  {step.eventInitDate.toUpperCase()}
        </Typography>
        </CardHeader>
      </Card>)
  }
const getShareWith = () => {
  return new Promise((res, rej)=>{
    setShareWith([
      {name: 'Organization (s)',
       data: fileData.accessOrg
      },
      {name: 'Company (s)',
        data: fileData.accessComp
      },
      {name: 'Department (s)',
        data: fileData.accessdept
      },
      {name: 'Team (s)',
        data: fileData.accessTeam
      },
      {name: 'User (s)',
        data: fileData.accessUser
      }
    ]);
    if (fileData.accessOrg.length == 0 && fileData.accessComp.length == 0 && fileData.accessdept.length == 0 && fileData.accessTeam.length == 0 && fileData.accessUser.length == 0 ) {
      setIsShared(false);
    }else{
      setIsShared(true);
    }
    res();
  })
}

const loadFunctions = async () => {
  setIsLoading(true);
  getQrCode().then(
    getShareWith().then(
      getFileVersions().then(
      fileData.initWorkFlow ?
      getBlockChainData().then(blockChainData=>{
        getWorkflowSteps().then(res=>{
          typeof res == 'object'?
          setWorkflow(res):setWorkflow(null);
          console.log(res);
          setIsLoading(false);
        });
      })
      :()=>{
        setIsLoading(false)
        setWorkflow(null)
    }
    )
  )
)
}

const getWorkflowSteps = async () => {
  //For Testing
  return new Promise((res,rej)=>{
    axios({
      method: "get",
      url: `${process.env.REACT_APP_LDOCS_API_WORKFLOW_URL}/workflow/getWorkflowDetailsByName/${fileData.workflowName}`,
      headers: { cooljwt: Token },
    })
  .then((response)=>{
    res(response.data);
  })
  .catch((err)=>{
    console.log(err);
  })
  })
};

const getFileVersions = async () => {
  return new Promise((res,rej)=>{
    axios({
      method: "get",
      url: `${process.env.REACT_APP_LDOCS_API_URL}/files/getFileVersions/${fileData.fileName}`,
      headers: { cooljwt: Token },
    })
  .then((response)=>{
    setVersions(response.data);
    res(response.data);
  })
  .catch((err)=>{
    console.log(err);
  })
  })
};


  useEffect(() => {
  loadFunctions();
  console.log(fileData);
  }, [fileData]);
  
  {
    return(
  isLoading ?
    <LinearProgress />: 
    <GridContainer ref={ref}>
          <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={blockChainData.length !== 0 ? 8 : 12}
              >
              <Card
                style={{ padding: "20px"}}
              >
              <Typography variant="h6" component="h2">
                 Document Details
              </Typography>
              <GridContainer 
                style={{ marginTop: "20px", marginBottom: "20px" }}
              >
              <GridItem
                xs={12}
                sm={12}
                md={4}
                lg={4}
              >
               <Typography variant="subtitle2" component="h2">
                 File Name
               </Typography>
               <Typography variant="body2" component="h2">
                 {fileData.fileName}
              </Typography>
              <Typography variant="subtitle2" component="h2">
                 File Description
               </Typography>
               <Typography variant="body2" component="h2">
                 {fileData.fileInitComments}
              </Typography>
              </GridItem>
              <GridItem
                xs={12}
                sm={12}
                md={4}
                lg={4}
              >
              <Typography variant="subtitle2" component="h2">
                File Owner
              </Typography>
              <Typography variant="body2" component="h2">
                 {fileData.fileOwner}
              </Typography>
              <Typography variant="subtitle2" component="h2">
                File Hash
              </Typography>
              <Typography variant="body2" component="h2">
                 {fileData.fileHash}
              </Typography>
              <Typography variant="subtitle2" component="h2">
                File Cretaed Date
              </Typography>
              <Typography variant="body2" component="h2">
                 {fileData.fileInitDate}
              </Typography>
              </GridItem>
              <GridItem
                xs={12}
                sm={12}
                md={4}
                lg={4}
                style={{ textAlign:'center' }}
              >
              <GridContainer>
              <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={12}
              >
              <FormControl variant="outlined" className={classes.formControl}>
                <InputLabel id="demo-simple-select-outlined-label">Version</InputLabel>
                <Select
                  labelId="demo-simple-select-outlined-label"
                  id="demo-simple-select-outlined"
                  value={version}
                  style={{width:150}}
                  onChange={Changehandler}
                  label="Version"
                >
                  {versions.map(vrsn=>{
                    return <MenuItem key={vrsn.version} value={vrsn.version}>Version {vrsn.version}</MenuItem>
                  })}
                </Select>
              </FormControl>
              </GridItem>
              <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={12}
              >
              <CopyToClipboard text={fileData.fileId}
                onCopy={() => setIsCopied(!isCopied)}>
              <img src={qrCode}  />
              </CopyToClipboard>
              </GridItem>
              <GridItem
                xs={12}
                sm={12}
                md={12}
                lg={12}
              >
              <CopyToClipboard text={fileData.fileId}
                onCopy={() => setIsCopied(!isCopied)}>
                <small style={{cursor:'pointer',color:isCopied?'blue':'black'}}>{isCopied ? 'Copied' : fileData.fileId.slice(0, 9)}....</small>
              </CopyToClipboard>          
              </GridItem>
              </GridContainer>
              </GridItem>
            </GridContainer>
            </Card>
            <GridContainer style={{marginTop:-20}}>
            {isShared ?
            <GridItem
              xs={12}
              sm={12}
              md={12}
              lg={6}
            >
              <Card
                style={{ padding: "20px"}}
              >
              <Typography variant="h6" component="h2">
                Access Members
              </Typography>
              <PerfectScrollbar 
              style={{marginTop:10}}
              >
              <List className={classesList.root} subheader={<li />}>
                {shareWith.length !== 0 ? shareWith.map((shrwth, index) => (
                  shrwth.data.length !== 0 ?
                  <li key={index} className={classesList.listSection}>
                    <ul className={classesList.ul}>
                      <ListSubheader style={{width:200}}>
                      <Typography variant="subtitle2" style={{fontWeight:800,color:'black'}} component="h2">
                        {shrwth.name}
                      </Typography>
                      </ListSubheader>
                      {shrwth.data.map((item, indx) => (
                        <ListItem key={`item-${index}-${indx}`}>
                          <small>{shrwth.name == 'User (s)' ? '-> ' + item.toUpperCase(): '-> ' + item.helperText.toUpperCase()}</small>
                        </ListItem>
                      ))}
                    </ul>
                  </li>:''
                )):''}
              </List>
              </PerfectScrollbar>
              </Card>
            </GridItem>:''}
            {workflow ?
            <GridItem
              xs={12}
              sm={12}
              md={12}
              lg={6}
            >
              <Card
                style={{ padding: "20px"}}
              >
              <Typography variant="h6" component="h2">
                 Workflow Steps
              </Typography> 
              <TableContainer>
            <Table className={classesList.table} aria-label="simple table">
            <TableHead>
                    <TableRow className={classesList.TableRow}>
                    <TableCell className={classesList.TableCell}>ID</TableCell>
                    <TableCell className={classesList.TableCell}>DESIGNTION</TableCell>
                    <TableCell className={classesList.TableCell}>ROLE</TableCell>
                    <TableCell className={classesList.TableCell}>STATUS</TableCell>
                </TableRow>
            </TableHead>
            <TableBody style={{paddingBottom:5}}>
                {workflow ? workflow.Steps.map((item, index)=>{
                    return (
                    <TableRow key={item.id}>
                        <TableCell className={classesList.TableCell}>{index+1}</TableCell>
                        <TableCell className={classesList.TableCell}>{item.Desigination}</TableCell>
                        <TableCell className={classesList.TableCell}>{item.Event}</TableCell>
                        <TableCell className={classesList.TableCell}>
                          {blockChainData.length*2 <= index ? <CheckCircleIcon fontSize="small"/>: <QueryBuilderIcon fontSize="small"/> }
                        </TableCell>
                    </TableRow>
                )}
                ):''}
            </TableBody>
            </Table>
            </TableContainer>
              </Card>
            </GridItem>
            :''}
            </GridContainer>
          </GridItem>
          {blockChainData.length !== 0 ? 
           <GridItem
           xs={12}
           sm={12}
           md={12}
           lg={4}
         >
         <Card
         style={{ padding: "10px"}}
         >
         <Typography variant="h6" component="h2">
            Workflow History
         </Typography>
         <Stepper  orientation="vertical" connector={<QontoConnector />}>
           {blockChainData.map((data, index) => (
               <Step active={true}  key={index}>
               <StepLabel >{JSON.parse(data.Record).docHash}</StepLabel>
               <StepContent>                
                   <div>{getStepContent(data, index)}</div>
               </StepContent>
               </Step>
           ))}
            </Stepper>
              </Card>
            </GridItem>
        :''
        }
         
    </GridContainer>
  );
}
});


export default FileAdvanceView;